def patch_display_label(patch_version: str | None = None) -> str:
    text = str(patch_version or PATCH_VERSION or "unknown").strip()
    match = re.match(r"^patch-(\d+)(?:-(.*))?$", text)
    if not match:
        return text
    suffix = " ".join(part for part in str(match.group(2) or "").split("-") if part).strip()
    return f"Patch {match.group(1)}{(' ' + suffix) if suffix else ''}"


def _dashboard_scanner_status_view(
    scanner_status: object,
    scanner_in_flight: object = False,
    last_event: object = None,
) -> dict:
    """Normalize scanner telemetry vocabulary for dashboard health.

    Render/worker telemetry uses both long-lived worker states (``ok``/``up``)
    and scan result states (``success``/``scan_ok``).  The dashboard should not
    show a component warning when the latest scanner event completed
    successfully but the persisted status string is ``success``.
    """
    status = str(scanner_status or "").strip().lower()
    event = str(last_event or "").strip().lower()
    in_flight = bool(scanner_in_flight)
    healthy_statuses = {
        "up",
        "ok",
        "healthy",
        "success",
        "scan_ok",
        "completed",
        "complete",
        "closed",
        "done",
        "ready",
    }
    healthy_events = {
        "scan_ok",
        "success",
        "completed",
        "scan_completed",
        "heartbeat",
        "scanner_heartbeat",
    }
    unhealthy_statuses = {
        "down",
        "stale",
        "error",
        "failed",
        "fail",
        "scan_error",
        "exception",
        "timeout",
    }
    unhealthy_events = {"scan_error", "error", "failed", "timeout", "exception"}
    if status in unhealthy_statuses or event in unhealthy_events:
        health = "unhealthy"
        ready = False
    elif status in healthy_statuses or event in healthy_events:
        health = "healthy"
        ready = True
    elif in_flight or status in {"running", "in_flight", "started", "scan_start"} or event in {"scan_start"}:
        health = "in_flight"
        ready = True
    elif status in {"received"} or event in {"received", "scan_request"}:
        health = "healthy"
        ready = True
    else:
        health = "unknown"
        ready = False
    return {
        "status": status or "unknown",
        "last_event": event or "",
        "in_flight": in_flight,
        "health": health,
        "healthy": health in {"healthy", "in_flight"},
        "ready": ready,
    }


def _dashboard_scanner_ready(scanner_status: object, scanner_in_flight: object = False, last_event: object = None) -> bool:
    return bool(_dashboard_scanner_status_view(scanner_status, scanner_in_flight, last_event).get("ready"))


def _dashboard_snapshot_age_view(snapshot_ts: object, generated_utc: object = None, *, stale_after_sec: int = 120) -> dict:
    """Return a dashboard-only freshness view without live broker calls."""
    generated_dt = _ts_parse_or_none(generated_utc) or datetime.now(timezone.utc)
    snapshot_dt = _ts_parse_or_none(snapshot_ts)
    stale_after = max(1, int(stale_after_sec or 120))
    warning_after = max(stale_after * 2, int(os.getenv("DASHBOARD_SNAPSHOT_WARNING_SEC", "300") or 300))
    critical_after = max(warning_after * 2, int(os.getenv("DASHBOARD_SNAPSHOT_CRITICAL_SEC", "600") or 600))
    if not snapshot_dt:
        return {
            "snapshot_ts": str(snapshot_ts or ""),
            "age_sec": None,
            "fresh": False,
            "severity": "critical",
            "status": "snapshot_missing",
            "note": "No persisted position snapshot timestamp is available; dashboard may lag broker truth until the worker writes a snapshot.",
        }
    age_sec = max(0, int((generated_dt.astimezone(timezone.utc) - snapshot_dt.astimezone(timezone.utc)).total_seconds()))
    fresh = age_sec <= stale_after
    if fresh:
        status = "fresh"
        severity = "good"
        note = "Snapshot is current enough for the read-only dashboard."
    elif age_sec <= warning_after:
        status = "mild_stale"
        severity = "warn"
        note = "Snapshot is mildly stale; dashboard may be a few minutes behind Alpaca until the worker writes the next snapshot."
    elif age_sec <= critical_after:
        status = "stale"
        severity = "warn"
        note = "Snapshot is stale; confirm worker exit/reconcile cycles are refreshing positions_snapshot.json."
    else:
        status = "critical_stale"
        severity = "critical"
        note = "Snapshot is critically stale; investigate worker heartbeat, exit worker, and persisted snapshot writes."
    return {
        "snapshot_ts": snapshot_dt.astimezone(timezone.utc).isoformat(),
        "age_sec": age_sec,
        "fresh": fresh,
        "severity": severity,
        "status": status,
        "thresholds": {"fresh_sec": stale_after, "warning_sec": warning_after, "critical_sec": critical_after},
        "note": note,
    }


def _dashboard_readiness_assessment(blockers: object, scanner_ready: object, launch_blockers: object = None) -> dict:
    blocker_list = list(blockers or []) if isinstance(blockers, (list, tuple, set)) else ([blockers] if blockers else [])
    launch_blocker_list = list(launch_blockers or []) if isinstance(launch_blockers, (list, tuple, set)) else ([launch_blockers] if launch_blockers else [])
    system_ready = not bool(blocker_list) and bool(scanner_ready)
    launch_ready = system_ready and not bool(launch_blocker_list)
    if launch_ready:
        status = "READY"
        css_class = "good"
    elif system_ready:
        status = "LAUNCH SETUP NEEDED"
        css_class = "neutral"
    else:
        status = "CHECK BLOCKERS"
        css_class = "neutral"
    return {
        "status": status,
        "class": css_class,
        "system_ready": system_ready,
        "intraday_launch_ready": launch_ready,
        "blocker_count": len(blocker_list),
        "launch_blocker_count": len(launch_blocker_list),
    }


def _unique_nonempty_actions(*groups: object) -> list[str]:
    actions: list[str] = []
    seen: set[str] = set()
    for group in groups:
        items = group if isinstance(group, (list, tuple, set)) else ([group] if group else [])
        for item in items:
            action = str(item or "").strip()
            if action and action not in seen:
                seen.add(action)
                actions.append(action)
    return actions


def _intraday_launch_gate_actions(launch_blockers: object) -> list[str]:
    blocker_list = list(launch_blockers or []) if isinstance(launch_blockers, (list, tuple, set)) else ([launch_blockers] if launch_blockers else [])
    blockers = {str(item or "").strip() for item in blocker_list if str(item or "").strip()}
    actions = []
    if {"market_not_tradable_now", "market_tradable_now"} & blockers:
        actions.append("wait_for_market_open")
    if {"regime_not_favorable", "regime_favorable"} & blockers:
        actions.append("wait_for_regime_favorable")
    if {"intraday_max_open_positions_not_above_base", "projected_intraday_open_slots_below_launch_min", "intraday_capacity_override_above_base", "projected_open_slots_meet_launch_min"} & blockers:
        actions.append("apply_intraday_capacity_env")
    if {"projected_intraday_open_slots_zero", "projected_open_slots_available"} & blockers:
        actions.append("free_slots_or_raise_intraday_max")
    return actions


def _intraday_launch_action_plan(
    gate_actions: object = None,
    required_actions: object = None,
    optional_scaling_actions: object = None,
    recommended_env: object = None,
) -> dict:
    env = dict(recommended_env or {}) if isinstance(recommended_env, dict) else {}
    return {
        "required_now": _unique_nonempty_actions(gate_actions, required_actions),
        "optional_scaling": _unique_nonempty_actions(optional_scaling_actions),
        "recommended_env": env,
    }
