def _live_loss_halt_checklist(halt_truth: dict | None, today_pnl: dict | None, flatten_decision: dict | None, open_orders: list | None = None) -> dict:
    halt = dict(halt_truth or {})
    pnl = dict(today_pnl or halt.get("today_pnl_truth") or {})
    decision = dict(flatten_decision or {})
    realized_halt = dict(halt.get("realized_closed_trade_loss_halt") or _p229_realized_closed_trade_loss_halt(pnl_truth=pnl))
    active = bool(halt.get("daily_halt_active") or daily_halt_active() or realized_halt.get("active"))
    new_entries_blocked = bool(active or (not NEW_ENTRIES_ENABLED) or (not is_live_trading_permitted("worker_scan")))
    exits_still_permitted = bool(is_live_exit_permitted("worker_exit", reason="daily_stop_hit" if active else ""))
    bulk_flatten_allowed = bool(decision.get("allow_bulk_flatten", globals().get("ALLOW_DAILY_STOP_BULK_FLATTEN", False)))
    recommended = []
    if active:
        recommended.extend(["monitor_existing_positions", "verify_open_orders", "do_not_enable_new_entries", "review_after_close"])
    elif open_orders:
        recommended.append("verify_open_orders")
    else:
        recommended.append("monitor")
    return {
        "daily_halt_active": active,
        "daily_halt_reason": halt.get("daily_halt_reason") or (DAILY_HALT_STATE or {}).get("reason") or "none",
        "account_daily_pnl": halt.get("account_daily_pnl") if halt.get("account_daily_pnl") is not None else pnl.get("account_daily_pnl"),
        "today_realized_pnl": pnl.get("today_realized_pnl"),
        "today_unrealized_pnl": pnl.get("today_unrealized_pnl"),
        "configured_daily_stop_dollars": halt.get("configured_daily_stop_dollars") or _configured_daily_stop_dollars_safe(),
        "realized_closed_trade_loss_halt": realized_halt,
        "new_entries_blocked": new_entries_blocked,
        "exits_still_permitted": exits_still_permitted,
        "bulk_flatten_allowed": bulk_flatten_allowed,
        "can_bulk_flatten_now": bool(decision.get("can_flatten", False)),
        "flatten_decision_reasons": list(decision.get("reasons") or []),
        "recommended_actions": recommended,
        "recommended_action": recommended[0],
        "open_order_count": len(list(open_orders or [])),
    }

def _p245_defensive_open_position_guard(symbol: str, plan: dict | None, pos: dict | None) -> dict:
    sym = str(symbol or "").upper()
    p = dict(plan or {})
    broker = dict(pos or {})
    signal = str(p.get("signal") or p.get("strategy_name") or "").strip().lower()
    mode = str(p.get("regime_mode") or ((p.get("thesis") or {}) if isinstance(p.get("thesis"), dict) else {}).get("regime_mode") or "").strip().lower()
    entry = _safe_float(broker.get("avg_entry_price") or p.get("entry_price") or p.get("avg_fill_price"), 0.0)
    stop = _safe_float(p.get("stop_price") or p.get("initial_stop_price"), 0.0)
    last = _safe_float(broker.get("current_price") or broker.get("last_price") or 0.0, 0.0)
    risk_pct = ((entry - stop) / max(entry, 1e-9)) if entry > 0 and stop > 0 else 0.0
    unrealized = _safe_float(broker.get("unrealized_pl"), 0.0)
    reasons = []

    if signal == BREAKOUT_STRATEGY_NAME and mode == "defensive":
        if risk_pct > float(SWING_DEFENSIVE_MAX_RISK_PER_SHARE_PCT):
            reasons.append("open_defensive_risk_per_share_above_patch245_guard")
        if last > 0 and stop > 0:
            distance_to_stop_pct = (last - stop) / max(last, 1e-9)
            if distance_to_stop_pct <= 0.01:
                reasons.append("open_defensive_near_stop")
        if unrealized < 0:
            reasons.append("open_defensive_unrealized_negative")

    return {
        "symbol": sym,
        "enabled": bool(SWING_DEFENSIVE_ENTRY_TIGHTENING_ENABLED),
        "advisory_only": True,
        "triggered": bool(reasons),
        "reasons": reasons,
        "entry_price": round(entry, 4) if entry > 0 else None,
        "last_price": round(last, 4) if last > 0 else None,
        "stop_price": round(stop, 4) if stop > 0 else None,
        "risk_per_share_pct": round(risk_pct * 100.0, 4),
        "unrealized_pl": round(unrealized, 4),
        "recommended_action": "monitor_tight_exit_behavior" if reasons else "none",
    }

def _p246_entry_quality_memory_guard(symbol: str, plan: dict | None, pos: dict | None) -> dict:
    sym = str(symbol or "").upper()
    p = dict(plan or {})
    thesis = dict(p.get("thesis") or {}) if isinstance(p.get("thesis"), dict) else {}
    snap = dict(thesis.get("entry_quality_snapshot") or {}) if isinstance(thesis.get("entry_quality_snapshot"), dict) else {}
    broker = dict(pos or {})

    mode = str(snap.get("regime_mode") or thesis.get("regime_mode") or p.get("regime_mode") or "").strip().lower()
    strategy = str(snap.get("strategy") or p.get("strategy_name") or p.get("signal") or "").strip().lower()
    return_20d = _safe_float(snap.get("return_20d_pct"), 0.0)
    risk_pct = _safe_float(snap.get("risk_per_share_pct"), 0.0)
    breakout_distance = _safe_float(snap.get("breakout_distance_pct"), 0.0)
    rank_score = snap.get("rank_score") if snap.get("rank_score") is not None else thesis.get("candidate_rank_score")
    reasons = []

    has_snapshot = bool(snap)
    if strategy == BREAKOUT_STRATEGY_NAME and mode == "defensive":
        if has_snapshot:
            if float(SWING_DEFENSIVE_MAX_20D_RETURN_PCT) > 0 and return_20d > float(SWING_DEFENSIVE_MAX_20D_RETURN_PCT) * 100.0:
                reasons.append("entry_memory_defensive_20d_return_too_extended")
            if float(SWING_DEFENSIVE_MAX_RISK_PER_SHARE_PCT) > 0 and risk_pct > float(SWING_DEFENSIVE_MAX_RISK_PER_SHARE_PCT) * 100.0:
                reasons.append("entry_memory_defensive_risk_per_share_too_wide")
        else:
            reasons.append("entry_quality_snapshot_missing")

    unrealized = _safe_float(broker.get("unrealized_pl"), 0.0)
    if unrealized < 0 and reasons:
        reasons.append("open_position_negative_with_entry_quality_warning")

    return {
        "symbol": sym,
        "enabled": True,
        "advisory_only": True,
        "has_entry_quality_snapshot": has_snapshot,
        "triggered": bool(reasons),
        "reasons": reasons,
        "entry_snapshot": {
            "strategy": strategy or None,
            "regime_mode": mode or None,
            "rank_score": rank_score,
            "return_20d_pct": return_20d if has_snapshot else None,
            "risk_per_share_pct": risk_pct if has_snapshot else None,
            "breakout_distance_pct": breakout_distance if has_snapshot else None,
            "defensive_tightening_enabled": snap.get("defensive_tightening_enabled"),
        },
        "current_unrealized_pl": round(unrealized, 4),
        "recommended_action": "monitor_or_tighten_exit_only" if reasons else "none",
    }


def _p246_entry_quality_memory_snapshot() -> dict:
    rows = []
    for sym, plan in list((TRADE_PLAN or {}).items()):
        if not isinstance(plan, dict) or not plan.get("active"):
            continue
        symbol = str(sym or plan.get("symbol") or "").upper()
        pos = {}
        try:
            for row in list_open_positions_details_allowed() or []:
                if str((row or {}).get("symbol") or "").upper() == symbol:
                    pos = dict(row or {})
                    break
        except Exception:
            pos = {}
        rows.append(_p246_entry_quality_memory_guard(symbol, plan, pos))
    triggered = [r for r in rows if r.get("triggered")]
    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "read_only_entry_quality_memory_guard",
        "active_position_count": len(rows),
        "triggered_count": len(triggered),
        "triggered_symbols": [r.get("symbol") for r in triggered],
        "rows": rows,
        "recommended_action": "review_triggered_positions_exit_plan" if triggered else "none",
    }

def _p250_entry_quality_exit_advisory(symbol: str, plan: dict | None, pos: dict | None) -> dict:
    sym = str(symbol or "").upper()
    p = dict(plan or {})
    broker = dict(pos or {})

    entry = _safe_float(
        broker.get("avg_entry_price")
        or p.get("entry_price")
        or p.get("avg_fill_price")
        or 0.0
    )
    last = _safe_float(
        broker.get("current_price")
        or broker.get("last_price")
        or p.get("last_price")
        or p.get("entry_price")
        or 0.0
    )
    stop = _safe_float(p.get("stop_price") or p.get("initial_stop_price") or 0.0)
    target = _safe_float(p.get("take_price") or p.get("target_price") or 0.0)
    qty = _safe_float(broker.get("qty") or p.get("qty") or p.get("quantity") or 0.0)
    side = str(p.get("side") or broker.get("side") or "buy").strip().lower()

    risk = _plan_risk_per_share(p)
    if risk <= 0 and entry > 0 and stop > 0:
        risk = abs(entry - stop)

    current_r = None
    if entry > 0 and last > 0 and risk > 0:
        if side in {"sell", "short"}:
            current_r = (entry - last) / risk
        else:
            current_r = (last - entry) / risk

    distance_to_stop_pct = None
    if last > 0 and stop > 0:
        distance_to_stop_pct = ((last - stop) / last) * 100.0

    distance_to_target_pct = None
    if last > 0 and target > 0:
        distance_to_target_pct = ((target - last) / last) * 100.0

    days_held = plan_days_held(p)
    memory_guard = _p246_entry_quality_memory_guard(sym, p, broker)

    stall_loss_guard_due = (
        bool(SWING_STALL_LOSS_GUARD_ENABLED)
        and current_r is not None
        and int(days_held or 0) >= int(SWING_STALL_LOSS_GUARD_DAYS or 0)
        and float(current_r) <= float(SWING_STALL_MAX_LOSS_R or -0.60)
    )
    stall_exit_due = (
        current_r is not None
        and int(SWING_STALL_EXIT_DAYS or 0) > 0
        and int(days_held or 0) >= int(SWING_STALL_EXIT_DAYS or 0)
        and float(current_r) < float(SWING_STALL_MIN_R or 0.0)
    )
    opening_damage_due = (
        current_r is not None
        and bool(SWING_OPENING_DAMAGE_GUARD_ENABLED)
        and float(current_r) <= float(SWING_OPENING_DAMAGE_MAX_LOSS_R or -1.10)
    )
    near_stop = distance_to_stop_pct is not None and distance_to_stop_pct <= 1.0

    reasons = []
    if memory_guard.get("triggered"):
        reasons.append("entry_quality_memory_flagged")
    if current_r is not None and current_r < 0:
        reasons.append("position_negative_r")
    if near_stop:
        reasons.append("within_1pct_of_stop")
    if stall_loss_guard_due:
        reasons.append("stall_loss_guard_due")
    if stall_exit_due:
        reasons.append("stall_exit_due")
    if opening_damage_due:
        reasons.append("opening_damage_guard_due")

    if stall_loss_guard_due or opening_damage_due:
        recommended_action = "exit_guard_likely_or_active"
    elif memory_guard.get("triggered") and (near_stop or (current_r is not None and current_r <= -0.50)):
        recommended_action = "tighten_exit_review"
    elif stall_exit_due:
        recommended_action = "stall_exit_review"
    elif memory_guard.get("triggered"):
        recommended_action = "monitor_flagged_entry"
    else:
        recommended_action = "allow_normal_hold"

    return {
        "symbol": sym,
        "mode": "read_only_entry_quality_exit_advisory",
        "advisory_only": True,
        "qty": round(qty, 6),
        "side": side,
        "entry_price": round(entry, 4) if entry > 0 else None,
        "last_price": round(last, 4) if last > 0 else None,
        "stop_price": round(stop, 4) if stop > 0 else None,
        "target_price": round(target, 4) if target > 0 else None,
        "risk_per_share": round(risk, 4) if risk > 0 else None,
        "current_r": round(float(current_r), 4) if current_r is not None else None,
        "days_held": int(days_held or 0),
        "distance_to_stop_pct": round(distance_to_stop_pct, 4) if distance_to_stop_pct is not None else None,
        "distance_to_target_pct": round(distance_to_target_pct, 4) if distance_to_target_pct is not None else None,
        "entry_quality_memory_guard": memory_guard,
        "stall_projection": {
            "stall_loss_guard_enabled": bool(SWING_STALL_LOSS_GUARD_ENABLED),
            "stall_loss_guard_days": int(SWING_STALL_LOSS_GUARD_DAYS or 0),
            "stall_max_loss_r": float(SWING_STALL_MAX_LOSS_R or 0.0),
            "stall_exit_days": int(SWING_STALL_EXIT_DAYS or 0),
            "stall_min_r": float(SWING_STALL_MIN_R or 0.0),
            "stall_loss_guard_due": bool(stall_loss_guard_due),
            "stall_exit_due": bool(stall_exit_due),
        },
        "opening_damage_projection": {
            "enabled": bool(SWING_OPENING_DAMAGE_GUARD_ENABLED),
            "max_loss_r": float(SWING_OPENING_DAMAGE_MAX_LOSS_R or 0.0),
            "guard_due": bool(opening_damage_due),
        },
        "triggered": bool(reasons),
        "reasons": reasons,
        "recommended_action": recommended_action,
    }


def _p250_entry_quality_exit_advisory_snapshot() -> dict:
    rows = []
    broker_by_symbol = {}

    try:
        for row in list_open_positions_details_allowed() or []:
            sym = str((row or {}).get("symbol") or "").upper()
            if sym:
                broker_by_symbol[sym] = dict(row or {})
    except Exception:
        broker_by_symbol = {}

    symbols = sorted({
        str(sym or "").upper()
        for sym, plan in (TRADE_PLAN or {}).items()
        if isinstance(plan, dict) and bool(plan.get("active"))
    } | set(broker_by_symbol.keys()))

    for sym in symbols:
        plan = dict((TRADE_PLAN or {}).get(sym) or {})
        pos = broker_by_symbol.get(sym) or {}
        if not plan and not pos:
            continue
        rows.append(_p250_entry_quality_exit_advisory(sym, plan, pos))

    tighten = [r for r in rows if r.get("recommended_action") in {"tighten_exit_review", "exit_guard_likely_or_active", "stall_exit_review"}]
    flagged = [r for r in rows if bool((r.get("entry_quality_memory_guard") or {}).get("triggered"))]

    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "read_only_entry_quality_flagged_exit_advisory_stall_projection",
        "active_position_count": len(rows),
        "entry_quality_flagged_count": len(flagged),
        "tighten_review_count": len(tighten),
        "flagged_symbols": [r.get("symbol") for r in flagged],
        "tighten_review_symbols": [r.get("symbol") for r in tighten],
        "rows": rows,
        "recommended_action": "review_tighten_candidates" if tighten else ("monitor_flagged_entries" if flagged else "none"),
    }

def _p251_today_symbol_loss_cooldown_rows(state: dict | None = None) -> list[dict]:
    preferred = _p245_broker_preferred_closed_rows(state or STRATEGY_PERFORMANCE_STATE)
    rows = []
    today = now_ny().date()

    for row in list(preferred.get("kept_rows") or []):
        r = dict(row or {})
        sym = str(r.get("symbol") or "").strip().upper()
        if not sym:
            continue

        ts = _p175_parse_dt(r.get("ts_utc") or r.get("closed_at") or r.get("exit_ts_utc"))
        if not ts:
            continue
        if ts.astimezone(NY_TZ).date() != today:
            continue

        pnl = _safe_float(r.get("gross_pnl"), 0.0)
        if pnl >= -abs(float(SWING_SAME_DAY_SYMBOL_LOSS_COOLDOWN_MIN_LOSS_DOLLARS or 0.01)):
            continue

        reason = str(r.get("reason") or r.get("exit_reason") or "").strip().lower()
        if reason == "opening_damage_exit" and not bool(SWING_SAME_DAY_SYMBOL_LOSS_COOLDOWN_INCLUDE_OPENING_DAMAGE):
            continue
        if reason in {"stall_loss_guard", "stall_exit"} and not bool(SWING_SAME_DAY_SYMBOL_LOSS_COOLDOWN_INCLUDE_STALL_LOSS):
            continue

        rows.append({
            "symbol": sym,
            "ts_utc": ts.astimezone(timezone.utc).isoformat(),
            "gross_pnl": round(pnl, 4),
            "reason": reason or None,
            "source": r.get("source"),
            "entry_price": r.get("entry_price"),
            "exit_price": r.get("exit_price"),
            "qty": r.get("qty"),
        })

    rows.sort(key=lambda x: str(x.get("ts_utc") or ""), reverse=True)
    return rows


def _p251_same_day_symbol_loss_cooldown(symbol: str, state: dict | None = None) -> dict:
    sym = str(symbol or "").strip().upper()
    rows = [r for r in _p251_today_symbol_loss_cooldown_rows(state=state) if str(r.get("symbol") or "").upper() == sym]
    active = bool(SWING_SAME_DAY_SYMBOL_LOSS_COOLDOWN_ENABLED and rows)
    blocked = bool(active and not SWING_SAME_DAY_SYMBOL_LOSS_COOLDOWN_ADVISORY_ONLY)
    return {
        "symbol": sym,
        "enabled": bool(SWING_SAME_DAY_SYMBOL_LOSS_COOLDOWN_ENABLED),
        "advisory_only": bool(SWING_SAME_DAY_SYMBOL_LOSS_COOLDOWN_ADVISORY_ONLY),
        "active": bool(active),
        "blocked": bool(blocked),
        "reason": "same_day_symbol_realized_loss" if active else "none",
        "loss_count_today": len(rows),
        "gross_pnl_today": round(sum(_safe_float(r.get("gross_pnl"), 0.0) for r in rows), 4),
        "rows": rows,
    }


def _p251_same_day_symbol_loss_cooldown_snapshot() -> dict:
    rows = _p251_today_symbol_loss_cooldown_rows()
    symbols = sorted({str(r.get("symbol") or "").upper() for r in rows if str(r.get("symbol") or "").strip()})
    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "same_day_symbol_loss_cooldown",
        "enabled": bool(SWING_SAME_DAY_SYMBOL_LOSS_COOLDOWN_ENABLED),
        "advisory_only": bool(SWING_SAME_DAY_SYMBOL_LOSS_COOLDOWN_ADVISORY_ONLY),
        "blocked_symbols": [] if SWING_SAME_DAY_SYMBOL_LOSS_COOLDOWN_ADVISORY_ONLY else symbols,
        "loss_symbols": symbols,
        "loss_count": len(rows),
        "gross_pnl": round(sum(_safe_float(r.get("gross_pnl"), 0.0) for r in rows), 4),
        "rows": rows,
        "recommended_action": "cooldown_active_for_loss_symbols" if symbols else "none",
    }

def _p252_swing_loss_day_entry_throttle_snapshot() -> dict:
    try:
        pnl = dict(today_pnl_truth_snapshot() or {})
    except Exception as exc:
        return {
            "ok": False,
            "patch_version": PATCH_VERSION,
            "mode": "swing_loss_day_entry_throttle",
            "enabled": bool(SWING_LOSS_DAY_ENTRY_THROTTLE_ENABLED),
            "active": False,
            "block_new_entries": False,
            "error": str(exc),
            "recommended_action": "monitor",
        }

    realized = _safe_float(pnl.get("today_realized_pnl"), 0.0)
    unrealized = _safe_float(pnl.get("today_unrealized_pnl"), 0.0)
    include_unrealized = bool(SWING_LOSS_DAY_ENTRY_THROTTLE_INCLUDE_UNREALIZED)
    loss_basis = realized + unrealized if include_unrealized else realized
    threshold = abs(float(SWING_LOSS_DAY_ENTRY_THROTTLE_REALIZED_LOSS_DOLLARS or 0.0))
    max_after = max(0, int(SWING_LOSS_DAY_ENTRY_THROTTLE_MAX_NEW_ENTRIES_AFTER_TRIGGER or 0))

    active = bool(
        SWING_LOSS_DAY_ENTRY_THROTTLE_ENABLED
        and threshold > 0
        and loss_basis <= -threshold
    )
    block_new_entries = bool(
        active
        and not SWING_LOSS_DAY_ENTRY_THROTTLE_ADVISORY_ONLY
        and max_after <= 0
    )

    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "swing_loss_day_entry_throttle",
        "enabled": bool(SWING_LOSS_DAY_ENTRY_THROTTLE_ENABLED),
        "advisory_only": bool(SWING_LOSS_DAY_ENTRY_THROTTLE_ADVISORY_ONLY),
        "active": bool(active),
        "block_new_entries": bool(block_new_entries),
        "max_new_entries_after_trigger": int(max_after),
        "include_unrealized": bool(include_unrealized),
        "loss_basis": "realized_plus_unrealized" if include_unrealized else "realized_only",
        "loss_basis_value": round(loss_basis, 4),
        "today_realized_pnl": round(realized, 4),
        "today_unrealized_pnl": round(unrealized, 4),
        "threshold_dollars": float(threshold),
        "accounting_source": pnl.get("accounting_source"),
        "broker_exit_fills_today": pnl.get("broker_exit_fills_today"),
        "closed_trades_today": pnl.get("closed_trades_today"),
        "recommended_action": "block_new_swing_entries_for_loss_day" if block_new_entries else ("limit_new_swing_entries_for_loss_day" if active else "none"),
    }

