def _dashboard_should_warn_on_freshness(*, stale_entries: list[str], missing_entries: list[str], session: dict | None = None) -> bool:
    stale = [str(item or "").strip() for item in (stale_entries or []) if str(item or "").strip()]
    missing = [str(item or "").strip() for item in (missing_entries or []) if str(item or "").strip()]
    if missing:
        return True
    if not stale:
        return False
    market_open_now = bool((session or {}).get("market_open_now"))
    if not market_open_now and set(stale) == {"regime"}:
        return False
    return True


def _dashboard_latest_completed_scan_summary() -> dict:
    def _usable_summary(scan_like: dict | None) -> dict:
        summary = dict((scan_like or {}).get("summary") or {})
        if not summary:
            return {}
        if summary.get("skipped"):
            return {}
        if summary.get("skip_reason"):
            return {}
        if summary.get("top_candidates") or summary.get("top_rejection_reasons") or summary.get("rejection_counts"):
            return summary
        return {}

    preferred = _usable_summary(LAST_SCAN if isinstance(LAST_SCAN, dict) else {})
    if preferred:
        return preferred

    for item in reversed(list(SCAN_HISTORY or [])):
        if not isinstance(item, dict):
            continue
        preferred = _usable_summary(item)
        if preferred:
            return preferred
    return {}



PATCH_175_FOCUS_REJECTION_REASONS = {
    "too_far_below_breakout",
    "close_not_near_high",
    "rank_score_below_min",
    "rank_below_threshold",
    "portfolio_exposure_limit",
    "daily_halt_active",
}


def _p175_float(value, default: float | None = None) -> float | None:
    try:
        if value in (None, ""):
            return default
        return float(value)
    except Exception:
        return default


def _p175_first(row: dict | None, *keys):
    row = row if isinstance(row, dict) else {}
    for key in keys:
        value = row.get(key)
        if value not in (None, ""):
            return value
    return None


def _p175_obj(value) -> dict:
    if isinstance(value, dict):
        return value
    if isinstance(value, str):
        text = value.strip()
        if text.startswith("{") and text.endswith("}"):
            try:
                parsed = json.loads(text)
                if isinstance(parsed, dict):
                    return parsed
            except Exception:
                return {}
    return {}


def _p175_parse_dt(value):
    try:
        parsed = _safe_parse_iso_utc(value)
        if parsed is not None:
            return parsed
    except Exception:
        pass
    try:
        if not value:
            return None
        if isinstance(value, (int, float)):
            ts = float(value)
            if ts > 1e12:
                ts = ts / 1000.0
            return datetime.fromtimestamp(ts, tz=timezone.utc)
        text = str(value).strip()
        if text.isdigit():
            ts = float(text)
            if ts > 1e12:
                ts = ts / 1000.0
            return datetime.fromtimestamp(ts, tz=timezone.utc)
        if text.endswith("Z"):
            text = text[:-1] + "+00:00"
        dt = datetime.fromisoformat(text)
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)
        return dt.astimezone(timezone.utc)
    except Exception:
        return None


def _p175_closed_trade_pnl(row: dict | None) -> float:
    value = _p175_first(row, "gross_pnl", "realized_pnl", "pnl", "profit_loss", "net_pnl")
    return float(_p175_float(value, 0.0) or 0.0)


def _p175_closed_trade_r(row: dict | None) -> float | None:
    return _p175_float(_p175_first(row, "pnl_r", "r", "r_multiple", "realized_r"), None)


def _p175_rank_score(row: dict | None) -> float | None:
    row = row if isinstance(row, dict) else {}
    thesis = _p175_obj(row.get("thesis"))
    meta = _p175_obj(row.get("meta"))
    rank_meta = _p175_obj(row.get("rank_meta"))
    thesis_meta = _p175_obj(row.get("thesis_meta"))
    selection_meta = _p175_obj(row.get("selection_meta"))
    score_meta = _p175_obj(row.get("score_meta"))
    for source in (row, thesis, meta, rank_meta, thesis_meta, selection_meta):
        score = _p175_first(
            source,
            "rank_score",
            "rank",
            "entry_rank_score",
            "candidate_rank_score",
            "signal_rank_score",
            "signal_rank",
            "raw_score",
            "score",
            "selection_quality_score",
        )
        parsed = _p175_float(score, None)
        if parsed is not None:
            return parsed
    comps = score_meta.get("components") if isinstance(score_meta.get("components"), dict) else {}
    for source in (score_meta, comps):
        parsed = _p175_float(_p175_first(source, "rank_score", "rank", "raw_score", "score"), None)
        if parsed is not None:
            return parsed
    return _p175_float(
        _p175_first(row, "rank_score", "rank", "entry_rank_score", "score", "selection_quality_score"),
        None,
    )


def _p175_rank_bucket(row: dict | None) -> str:
    score = _p175_rank_score(row)
    if score is None:
        return "unknown"
    if score < 40:
        return "<40"
    if score < 50:
        return "40-49.99"
    if score < 60:
        return "50-59.99"
    if score < 70:
        return "60-69.99"
    if score < 80:
        return "70-79.99"
    return "80+"


def _p175_holding_days(row: dict | None) -> float | None:
    row = row if isinstance(row, dict) else {}
    entry = _p175_obj(row.get("entry"))
    exit_data = _p175_obj(row.get("exit"))
    direct = _p175_float(_p175_first(row, "holding_days", "hold_days", "days_held", "holding_period_days"), None)
    if direct is not None:
        return direct
    hours = _p175_float(_p175_first(row, "holding_hours", "hold_hours", "holding_period_hours"), None)
    if hours is not None:
        return hours / 24.0
    entry_dt = _p175_parse_dt(
        _p175_first(
            row, "entry_ts_utc", "entry_utc", "entry_time", "entry_timestamp", "opened_at_utc", "opened_at", "submitted_at", "created_at"
        ) or _p175_first(entry, "ts_utc", "timestamp", "time", "submitted_at", "filled_at", "opened_at")
    )
    exit_dt = _p175_parse_dt(
        _p175_first(
            row, "ts_utc", "exit_ts_utc", "exit_utc", "closed_at_utc", "exit_time", "closed_at", "updated_at"
        ) or _p175_first(exit_data, "ts_utc", "timestamp", "time", "closed_at", "filled_at")
    )
    if entry_dt and exit_dt and exit_dt >= entry_dt:
        return (exit_dt - entry_dt).total_seconds() / 86400.0
    return None


def _p175_holding_bucket(row: dict | None) -> str:
    days = _p175_holding_days(row)
    if days is None:
        return "unknown"
    if days < 1:
        return "intraday"
    if days < 2:
        return "1 day"
    if days < 4:
        return "2-3 days"
    if days < 8:
        return "4-7 days"
    if days < 15:
        return "8-14 days"
    return "15+ days"


def _p175_enrich_closed_trade_row(row: dict | None) -> tuple[dict, bool]:
    out = dict(row or {})
    changed = False
    if _p175_rank_score(out) is None:
        inferred_rank = _p175_float(_p175_first(out, "candidate_rank_score", "signal_rank", "signal_rank_score"), None)
        if inferred_rank is not None:
            out["rank_score"] = inferred_rank
            changed = True
    if _p175_holding_days(out) is None:
        inferred_holding = _p175_float(_p175_first(out, "holding_period", "hold_period"), None)
        if inferred_holding is not None:
            out["holding_days"] = float(inferred_holding)
            changed = True
    return out, changed


def _p175_enrich_closed_trades_state(state: dict | None) -> tuple[dict, dict]:
    state = dict(state or {})
    closed = list(state.get("closed_trades") or [])
    out = []
    changed_count = 0
    for row in closed:
        enriched, changed = _p175_enrich_closed_trade_row(row if isinstance(row, dict) else {})
        out.append(enriched)
        changed_count += int(bool(changed))
    state["closed_trades"] = out
    return state, {"rows_seen": len(closed), "rows_changed": changed_count, "changed": bool(changed_count)}




def _p175_scan_ts(scan: dict | None):
    scan = scan if isinstance(scan, dict) else {}
    return _p175_first(scan, "ts_utc", "last_closed_utc", "saved_at_utc", "generated_utc")


def _p175_scan_candidates(scan: dict | None) -> list[dict]:
    scan = scan if isinstance(scan, dict) else {}
    summary = scan.get("summary") if isinstance(scan.get("summary"), dict) else {}
    rows = scan.get("candidates") or scan.get("results") or scan.get("last_swing_candidates") or summary.get("top_candidates") or []
    return [dict(row) for row in rows if isinstance(row, dict)]


def _p175_rejection_follow_through(scan_history: list[dict], start_idx: int, symbol: str, base_close: float | None) -> dict:
    if not symbol or not base_close or base_close <= 0:
        return {"observations": 0}
    returns = []
    examples = []
    for future_scan in scan_history[start_idx + 1:]:
        ts = _p175_scan_ts(future_scan)
        for future_row in _p175_scan_candidates(future_scan):
            if str(future_row.get("symbol") or "").upper() != symbol:
                continue
            future_close = _p175_float(_p175_first(future_row, "close", "price", "last"), None)
            if future_close is None or future_close <= 0:
                continue
            move_pct = ((future_close - base_close) / base_close) * 100.0
            returns.append(move_pct)
            if len(examples) < 3:
                examples.append({"ts_utc": ts, "close": round(future_close, 4), "move_pct": round(move_pct, 4)})
    if not returns:
        return {"observations": 0}
    return {
        "observations": len(returns),
        "best_follow_through_pct": round(max(returns), 4),
        "worst_follow_through_pct": round(min(returns), 4),
        "last_follow_through_pct": round(returns[-1], 4),
        "positive_follow_through": bool(max(returns) > 0),
        "examples": examples,
    }

def _p175_bucket_summary(rows: list[dict], key_fn) -> dict:
    out: dict[str, dict] = {}
    for raw in rows or []:
        row = raw if isinstance(raw, dict) else {}
        key = str(key_fn(row) or "unknown")
        bucket = out.setdefault(key, {"closed_trades": 0, "wins": 0, "losses": 0, "flat": 0, "gross_pnl": 0.0, "avg_r": None, "_r_sum": 0.0, "_r_count": 0})
        pnl = _p175_closed_trade_pnl(row)
        bucket["closed_trades"] += 1
        bucket["gross_pnl"] += pnl
        if pnl > 0:
            bucket["wins"] += 1
        elif pnl < 0:
            bucket["losses"] += 1
        else:
            bucket["flat"] += 1
        r_value = _p175_closed_trade_r(row)
        if r_value is not None:
            bucket["_r_sum"] += r_value
            bucket["_r_count"] += 1
    for bucket in out.values():
        count = max(1, int(bucket.get("closed_trades") or 0))
        bucket["gross_pnl"] = round(float(bucket.get("gross_pnl") or 0.0), 4)
        bucket["win_rate"] = round(float(bucket.get("wins") or 0) / count, 4)
        r_count = int(bucket.pop("_r_count") or 0)
        r_sum = float(bucket.pop("_r_sum") or 0.0)
        bucket["avg_r"] = round(r_sum / r_count, 4) if r_count else None
    return dict(sorted(out.items(), key=lambda kv: (kv[0] == "unknown", kv[0])))


def _p175_trade_quality_analytics(
    *,
    perf_state: dict | None = None,
    position_snapshot: dict | None = None,
    scan_state: dict | None = None,
    recent_scan_limit: int = 25,
) -> dict:
    perf_state = perf_state if isinstance(perf_state, dict) else dict(STRATEGY_PERFORMANCE_STATE or {})
    position_snapshot = position_snapshot if isinstance(position_snapshot, dict) else _safe_json_read(POSITION_SNAPSHOT_PATH)
    scan_state = scan_state if isinstance(scan_state, dict) else _safe_json_read(SCAN_STATE_PATH)
    closed_rows = [dict(r) for r in list(perf_state.get("closed_trades") or []) if isinstance(r, dict)]

    def symbol_key(row):
        return str(row.get("symbol") or "unknown").upper() or "unknown"

    def strategy_key(row):
        return str(row.get("strategy_name") or row.get("strategy") or row.get("signal") or row.get("entry_signal") or "unknown").strip().lower() or "unknown"

    def exit_key(row):
        return str(row.get("exit_reason") or row.get("reason") or row.get("close_reason") or "unknown").strip().lower() or "unknown"

    positions = [dict(p) for p in list(position_snapshot.get("positions") or []) if isinstance(p, dict)]
    plans = position_snapshot.get("active_plans") if isinstance(position_snapshot.get("active_plans"), dict) else {}
    open_rows = []
    total_notional = total_risk = total_unrealized = 0.0
    symbols = sorted({str((p or {}).get("symbol") or "").upper() for p in positions if str((p or {}).get("symbol") or "").strip()} | {str(s or "").upper() for s, plan in plans.items() if isinstance(plan, dict) and plan.get("active")})
    for sym in symbols:
        pos = next((p for p in positions if str(p.get("symbol") or "").upper() == sym), {})
        plan = plans.get(sym) if isinstance(plans.get(sym), dict) else {}
        qty = abs(float(_p175_float(_p175_first(pos, "qty") or _p175_first(plan, "filled_qty", "qty", "requested_qty"), 0.0) or 0.0))
        entry = float(_p175_float(_p175_first(pos, "avg_entry_price") or _p175_first(plan, "entry_price", "avg_fill_price"), 0.0) or 0.0)
        last = float(_p175_float(_p175_first(pos, "current_price", "last_price", "latest_price", "market_price") or _p175_first(plan, "last_price", "current_price"), entry) or 0.0)
        stop = float(_p175_float(_p175_first(plan, "stop_price", "initial_stop_price"), 0.0) or 0.0)
        side = str(_p175_first(plan, "side") or "buy").lower()
        notional = qty * (last or entry)
        risk = qty * abs((entry - stop) if side != "sell" else (stop - entry)) if entry > 0 and stop > 0 else 0.0
        unreal = _p175_float(_p175_first(pos, "unrealized_pl", "unrealized_intraday_pl"), None)
        if unreal is None and qty > 0 and entry > 0 and last > 0:
            unreal = (last - entry) * qty if side != "sell" else (entry - last) * qty
        unreal = float(unreal or 0.0)
        total_notional += notional
        total_risk += risk
        total_unrealized += unreal
        open_rows.append({"symbol": sym, "qty": qty, "entry_price": entry or None, "last_price": last or None, "stop_price": stop or None, "notional": round(notional, 2), "risk_to_stop": round(risk, 2), "unrealized_pl": round(unreal, 2), "rank_score": _p175_rank_score(plan), "strategy": strategy_key(plan)})

    scan_history = [dict(scan) for scan in list(scan_state.get("scan_history") or [])[-max(1, min(int(recent_scan_limit or 25), 100)):] if isinstance(scan, dict)]
    reason_buckets: dict[str, dict] = {}
    for scan_idx, scan_row in enumerate(scan_history):
        candidates = _p175_scan_candidates(scan_row)
        scan_ts = _p175_scan_ts(scan_row)
        for row in candidates:
            reasons = [str(r).strip() for r in list(row.get("rejection_reasons") or row.get("reasons") or row.get("selection_blockers") or []) if str(r).strip()]
            sym = str(row.get("symbol") or "").upper()
            score = _p175_rank_score(row)
            close = _p175_float(_p175_first(row, "close", "price", "last"), None)
            follow = _p175_rejection_follow_through(scan_history, scan_idx, sym, close)
            for reason in reasons:
                bucket = reason_buckets.setdefault(reason, {
                    "count": 0,
                    "symbols": {},
                    "avg_rank_score": None,
                    "_rank_sum": 0.0,
                    "_rank_count": 0,
                    "follow_through_count": 0,
                    "positive_follow_through_count": 0,
                    "_best_follow_sum": 0.0,
                    "_last_follow_sum": 0.0,
                    "latest_examples": [],
                })
                bucket["count"] += 1
                if sym:
                    bucket["symbols"][sym] = int(bucket["symbols"].get(sym) or 0) + 1
                if score is not None:
                    bucket["_rank_sum"] += score
                    bucket["_rank_count"] += 1
                if int(follow.get("observations") or 0) > 0:
                    bucket["follow_through_count"] += 1
                    bucket["_best_follow_sum"] += float(follow.get("best_follow_through_pct") or 0.0)
                    bucket["_last_follow_sum"] += float(follow.get("last_follow_through_pct") or 0.0)
                    if bool(follow.get("positive_follow_through")):
                        bucket["positive_follow_through_count"] += 1
                if reason in PATCH_175_FOCUS_REJECTION_REASONS and len(bucket["latest_examples"]) < 8:
                    bucket["latest_examples"].append({
                        "ts_utc": scan_ts,
                        "symbol": sym,
                        "rank_score": score,
                        "close": close,
                        "breakout_distance_pct": row.get("breakout_distance_pct"),
                        "close_to_high_pct": row.get("close_to_high_pct"),
                        "follow_through": follow,
                    })
    for reason, bucket in reason_buckets.items():
        rc = int(bucket.pop("_rank_count") or 0)
        rs = float(bucket.pop("_rank_sum") or 0.0)
        follow_count = int(bucket.get("follow_through_count") or 0)
        positive_count = int(bucket.get("positive_follow_through_count") or 0)
        best_sum = float(bucket.pop("_best_follow_sum") or 0.0)
        last_sum = float(bucket.pop("_last_follow_sum") or 0.0)
        bucket["avg_rank_score"] = round(rs / rc, 4) if rc else None
        bucket["avg_best_follow_through_pct"] = round(best_sum / follow_count, 4) if follow_count else None
        bucket["avg_last_follow_through_pct"] = round(last_sum / follow_count, 4) if follow_count else None
        bucket["positive_follow_through_rate"] = round(positive_count / follow_count, 4) if follow_count else None
        bucket["unique_symbols"] = len(bucket.get("symbols") or {})
        bucket["top_symbols"] = [{"symbol": sym, "count": count} for sym, count in sorted((bucket.pop("symbols") or {}).items(), key=lambda kv: (-kv[1], kv[0]))[:8]]
    focus = {
        reason: reason_buckets.get(reason, {
            "count": 0,
            "unique_symbols": 0,
            "avg_rank_score": None,
            "follow_through_count": 0,
            "avg_best_follow_through_pct": None,
            "avg_last_follow_through_pct": None,
            "positive_follow_through_rate": None,
            "top_symbols": [],
            "latest_examples": [],
        })
        for reason in sorted(PATCH_175_FOCUS_REJECTION_REASONS)
    }

    return {
        "ok": True,
        "patch": "175",
        "read_only": True,
        "closed_trade_count": len(closed_rows),
        "missing_field_counts": {
            "rank_score": sum(1 for r in closed_rows if _p175_rank_score(r) is None),
            "holding_period": sum(1 for r in closed_rows if _p175_holding_days(r) is None),
            "exit_reason": sum(1 for r in closed_rows if not _p175_first(r, "exit_reason", "reason", "close_reason")),
            "strategy": sum(1 for r in closed_rows if not _p175_first(r, "strategy_name", "strategy", "signal", "entry_signal")),
        },
        "closed_trades_by_rank_bucket": _p175_bucket_summary(closed_rows, _p175_rank_bucket),
        "closed_trades_by_symbol": _p175_bucket_summary(closed_rows, symbol_key),
        "closed_trades_by_holding_period": _p175_bucket_summary(closed_rows, _p175_holding_bucket),
        "closed_trades_by_strategy": _p175_bucket_summary(closed_rows, strategy_key),
        "closed_trades_by_exit_reason": _p175_bucket_summary(closed_rows, exit_key),
        "open_book_risk": {
            "open_positions": len(open_rows),
            "max_open_positions": int(_effective_max_open_positions()),
            "total_notional": round(total_notional, 2),
            "total_risk_to_stop": round(total_risk, 2),
            "total_unrealized_pl": round(total_unrealized, 2),
            "portfolio_exposure_cap_pct": float(_effective_portfolio_exposure_cap_pct()),
            "symbol_exposure_cap_pct": float(_effective_symbol_exposure_cap_pct()),
            "rows": open_rows,
        },
        "rejected_setup_follow_through": {
            "recent_scan_count": len(scan_history),
            "focus_reasons": focus,
            "all_reasons": dict(sorted(reason_buckets.items(), key=lambda kv: (-int(kv[1].get("count") or 0), kv[0]))),
            "note": "Read-only summary of persisted rejected setup rows. Follow-through uses later persisted scan closes for the same symbol when available; older rows without later closes remain counted without invented returns.",
        },
    }
    

def _p207_closed_trade_strategy(row: dict | None) -> str:
    row = row if isinstance(row, dict) else {}
    return str(_p175_first(row, "strategy_name", "strategy", "signal", "entry_signal") or "unknown").strip().lower() or "unknown"


def _p207_closed_trade_entry_type(row: dict | None) -> str:
    row = row if isinstance(row, dict) else {}
    source = str(_p175_first(row, "entry_type", "selected_source", "source", "submit_source") or "standard").strip().lower() or "standard"
    if "early" in source:
        return "early_override"
    if "adaptive" in source:
        return "adaptive"
    if source in {"worker_scan", "scanner", "standard", "daily_breakout", "daily_mean_reversion"}:
        return "standard"
    return source


def _p207_closed_trade_exit_reason(row: dict | None) -> str:
    return str(_p175_first(row if isinstance(row, dict) else {}, "exit_reason", "reason", "close_reason", "exit_type") or "unknown").strip().lower() or "unknown"



def _p208_trade_drilldown_row(row: dict | None) -> dict:
    row = row if isinstance(row, dict) else {}
    return {
        "symbol": str(row.get("symbol") or "unknown").upper() or "unknown",
        "strategy": _p207_closed_trade_strategy(row),
        "entry_type": _p207_closed_trade_entry_type(row),
        "exit_reason": _p207_closed_trade_exit_reason(row),
        "holding_days": _p175_holding_days(row),
        "regime_mode": str(_p175_first(row, "entry_regime_mode", "regime_mode", "regime") or "unknown").strip().lower() or "unknown",
        "rank_score": _p175_rank_score(row),
        "gross_pnl": round(_p175_closed_trade_pnl(row), 4),
        "pnl_r": _p175_closed_trade_r(row),
        "ts_utc": _p175_first(row, "ts_utc", "exit_ts_utc", "closed_at", "updated_at"),
    }


def _p208_worst_trade_contributors(rows: list[dict], limit: int = 10) -> list[dict]:
    drilldown = [_p208_trade_drilldown_row(r) for r in rows or []]
    drilldown = [r for r in drilldown if r.get("pnl_r") is not None]
    return sorted(drilldown, key=lambda r: (float(r.get("pnl_r") or 0.0), float(r.get("gross_pnl") or 0.0)))[: max(1, int(limit or 10))]


def _p208_risk_blocker_explanation(rows: list[dict], risk_scaling: dict | None = None) -> dict:
    risk_scaling = risk_scaling if isinstance(risk_scaling, dict) else {}
    threshold = float(SWING_PERFORMANCE_RISK_SCALE_MAX_WORST_R)
    worst_rows = _p208_worst_trade_contributors(rows, limit=10)
    offenders = [r for r in worst_rows if r.get("pnl_r") is not None and float(r.get("pnl_r") or 0.0) < threshold]
    primary = offenders[0] if offenders else (worst_rows[0] if worst_rows else {})
    if offenders:
        next_fix = "inspect_worst_r_trade_and_tighten_bucket_or_quarantine"
    elif "avg_r_below_40_risk_min" in list(risk_scaling.get("blockers") or []):
        next_fix = "improve_avg_r_before_scaling_risk"
    elif "win_rate_below_risk_scale_min" in list(risk_scaling.get("blockers") or []):
        next_fix = "improve_win_rate_before_scaling_risk"
    elif "sample_below_risk_scale_min" in list(risk_scaling.get("blockers") or []):
        next_fix = "collect_more_closed_trades_before_scaling_risk"
    else:
        next_fix = "risk_scaling_clear_or_no_specific_blocker"
    return {
        "worst_r_too_deep": bool(offenders),
        "worst_r_threshold": threshold,
        "offending_trades": offenders,
        "worst_trade": primary,
        "worst_r_symbol": primary.get("symbol"),
        "worst_r_exit_reason": primary.get("exit_reason"),
        "worst_r_strategy": primary.get("strategy"),
        "risk_scale_next_required_fix": next_fix,
    }


def _swing_quarantine_decision(symbol: str = "", strategy: str = "", entry_type: str = "") -> dict:
    sym = str(symbol or "").strip().upper()
    strat = str(strategy or "").strip().lower()
    etype = str(entry_type or "").strip().lower()
    reasons = []
    if sym and sym in SWING_QUARANTINE_SYMBOLS:
        reasons.append("symbol_quarantined")
    if strat and strat in SWING_QUARANTINE_STRATEGIES:
        reasons.append("strategy_quarantined")
    if etype and etype in SWING_QUARANTINE_ENTRY_TYPES:
        reasons.append("entry_type_quarantined")
    return {
        "blocked": bool(SWING_QUARANTINE_ENFORCE and reasons),
        "matched": bool(reasons),
        "enforced": bool(SWING_QUARANTINE_ENFORCE),
        "reasons": reasons,
        "symbol": sym,
        "strategy": strat,
        "entry_type": etype,
    }

def _p210_safe_dict(v: object) -> dict:
    return v if isinstance(v, dict) else {}


def _p210_safe_list(v: object) -> list:
    return list(v) if isinstance(v, list) else []


def _p210_trade_bucket_value(row: dict | None, category: str) -> str:
    row = row if isinstance(row, dict) else {}
    category = str(category or "").strip().lower()
    if category == "symbols":
        return str(row.get("symbol") or "unknown").strip().upper() or "unknown"
    if category == "strategies":
        return _p207_closed_trade_strategy(row)
    if category == "entry_types":
        return _p207_closed_trade_entry_type(row)
    if category == "exit_reasons":
        return _p207_closed_trade_exit_reason(row)
    if category == "holding_periods":
        return _p175_holding_bucket(row)
    if category == "regime_modes":
        return str(_p175_first(row, "entry_regime_mode", "regime_mode", "regime") or "unknown").strip().lower() or "unknown"
    return "unknown"


def _p210_rows_summary(rows: list[dict]) -> dict:
    totals_list = _p207_bucket_summary(rows, lambda _r: "all")
    totals = totals_list[0] if totals_list else {"name": "all", "closed_trades": 0, "wins": 0, "losses": 0, "flat": 0, "gross_pnl": 0.0, "win_rate": 0.0, "avg_r": 0.0, "worst_r": None, "best_r": None}
    risk = _p207_risk_scaling_readiness(rows, totals)
    return {"totals": totals, "risk_scaling": risk}


def _p210_candidate_keys(rows: list[dict], attribution: dict | None = None) -> list[dict]:
    attribution = attribution if isinstance(attribution, dict) else {}
    candidates: dict[tuple[str, str], dict] = {}

    def add(category: str, name: object, source: str):
        cat = str(category or "").strip().lower()
        val = str(name or "").strip()
        if not cat or not val or val.lower() == "unknown":
            return
        key = (cat, val.upper() if cat == "symbols" else val.lower())
        row = candidates.setdefault(key, {"category": cat, "name": key[1], "sources": []})
        if source and source not in row["sources"]:
            row["sources"].append(source)

    for trade in _p210_safe_list(attribution.get("worst_trade_contributors"))[:10]:
        row = _p210_safe_dict(trade)
        add("symbols", row.get("symbol"), "worst_trade")
        add("strategies", row.get("strategy"), "worst_trade")
        add("exit_reasons", row.get("exit_reason"), "worst_trade")
        if row.get("holding_days") is not None:
            add("holding_periods", _p175_holding_bucket({"holding_days": row.get("holding_days")}), "worst_trade")
        add("regime_modes", row.get("regime_mode"), "worst_trade")

    for action_name in ("quarantine", "reduce"):
        for rec in _p210_safe_list(_p210_safe_dict(attribution.get("recommendations")).get(action_name)):
            r = _p210_safe_dict(rec)
            add(r.get("category"), r.get("name"), f"{action_name}_recommendation")

    for bucket_category, rows_key in (("symbols", "by_symbol"), ("strategies", "by_strategy"), ("entry_types", "by_entry_type"), ("exit_reasons", "by_exit_reason"), ("holding_periods", "by_holding_period")):
        for bucket in _p210_safe_list(attribution.get(rows_key)):
            b = _p210_safe_dict(bucket)
            if int(b.get("closed_trades") or 0) < max(1, int(SWING_PERFORMANCE_MIN_TRADES_PER_BUCKET or 1)):
                continue
            if float(b.get("gross_pnl") or 0.0) < 0 or (_p175_float(b.get("avg_r"), 0.0) or 0.0) <= float(SWING_PERFORMANCE_REDUCE_MAX_AVG_R):
                add(bucket_category, b.get("name"), "weak_bucket")

    return list(candidates.values())


def _swing_damage_guard_snapshot() -> dict:
    rows = []
    for symbol, plan in list((TRADE_PLAN or {}).items()):
        if not isinstance(plan, dict) or not bool(plan.get("active")):
            continue
        sym = str(symbol or plan.get("symbol") or "").upper()
        if not sym:
            continue
        try:
            qty_signed, _pos_side = get_position(sym)
        except Exception:
            qty_signed = 0
        try:
            px = get_latest_price(sym) if qty_signed != 0 else 0.0
        except Exception:
            px = 0.0
        guard = _swing_opening_damage_guard(sym, plan, float(px)) if px > 0 else {
            "enabled": bool(SWING_OPENING_DAMAGE_GUARD_ENABLED),
            "triggered": False,
            "reason": "latest_price_unavailable",
            "symbol": sym,
        }
        rows.append({
            "symbol": sym,
            "active": bool(plan.get("active")),
            "broker_position_qty": qty_signed,
            "price": round(float(px), 4) if px else None,
            "entry_price": plan.get("entry_price"),
            "stop_price": plan.get("stop_price"),
            "initial_stop_price": plan.get("initial_stop_price"),
            "take_price": plan.get("take_price"),
            "days_held": plan_days_held(plan),
            "damage_guard": guard,
        })
    triggered = [r for r in rows if bool((r.get("damage_guard") or {}).get("triggered"))]
    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "strategy_mode": STRATEGY_MODE,
        "market_open": bool(in_market_hours()),
        "enabled": bool(SWING_OPENING_DAMAGE_GUARD_ENABLED),
        "max_loss_r": float(SWING_OPENING_DAMAGE_MAX_LOSS_R),
        "grace_min": int(SWING_OPENING_DAMAGE_GRACE_MIN),
        "positions_checked": len(rows),
        "triggered_count": len(triggered),
        "triggered_symbols": [r.get("symbol") for r in triggered],
        "positions": rows,
    }

def _swing_profit_acceleration_simulator(perf_state: dict | None = None) -> dict:
    state = perf_state if isinstance(perf_state, dict) else _recompute_strategy_performance_state()
    state, _ = _patch175_enrich_state_if_needed(state)
    rows = [dict(r) for r in list((state or {}).get("closed_trades") or []) if isinstance(r, dict)]
    baseline = _p210_rows_summary(rows)
    attribution = _swing_performance_attribution(perf_state=state)
    base_totals = _p210_safe_dict(baseline.get("totals"))
    base_gross = float(base_totals.get("gross_pnl") or 0.0)
    base_avg_r = _p175_float(base_totals.get("avg_r"), 0.0) or 0.0
    base_win_rate = _p175_float(base_totals.get("win_rate"), 0.0) or 0.0
    scenarios = []

    for candidate in _p210_candidate_keys(rows, attribution):
        category = str(candidate.get("category") or "")
        name = str(candidate.get("name") or "")
        removed = [r for r in rows if _p210_trade_bucket_value(r, category) == name]
        if len(removed) < max(1, int(SWING_TUNING_SIM_MIN_REMOVED_TRADES or 1)):
            continue
        kept = [r for r in rows if _p210_trade_bucket_value(r, category) != name]
        removed_summary = _p210_rows_summary(removed)
        after_summary = _p210_rows_summary(kept)
        after_totals = _p210_safe_dict(after_summary.get("totals"))
        after_risk = _p210_safe_dict(after_summary.get("risk_scaling"))
        scenario = {
            "category": category,
            "name": name,
            "sources": list(candidate.get("sources") or []),
            "action": "simulate_filter_bucket",
            "trades_removed": len(removed),
            "trades_remaining": len(kept),
            "removed_gross_pnl": round(float(_p210_safe_dict(removed_summary.get("totals")).get("gross_pnl") or 0.0), 4),
            "removed_avg_r": _p210_safe_dict(removed_summary.get("totals")).get("avg_r"),
            "simulated_gross_pnl": round(float(after_totals.get("gross_pnl") or 0.0), 4),
            "gross_pnl_delta": round(float(after_totals.get("gross_pnl") or 0.0) - base_gross, 4),
            "simulated_win_rate": after_totals.get("win_rate"),
            "win_rate_delta": round(float(after_totals.get("win_rate") or 0.0) - base_win_rate, 4),
            "simulated_avg_r": after_totals.get("avg_r"),
            "avg_r_delta": round(float(after_totals.get("avg_r") or 0.0) - base_avg_r, 4),
            "simulated_worst_r": after_totals.get("worst_r"),
            "ready_for_40_risk_after": bool(after_risk.get("ready_for_40_risk")),
            "ready_for_50_risk_after": bool(after_risk.get("ready_for_50_risk")),
            "risk_blockers_after": list(after_risk.get("blockers") or []),
            "recommended_next_step": "consider_quarantine_or_tighten_filter" if float(after_totals.get("gross_pnl") or 0.0) > base_gross else "do_not_filter_without_more_proof",
        }
        scenarios.append(scenario)

    scenarios = sorted(
        scenarios,
        key=lambda r: (
            bool(r.get("ready_for_50_risk_after")),
            bool(r.get("ready_for_40_risk_after")),
            float(r.get("gross_pnl_delta") or 0.0),
            float(r.get("avg_r_delta") or 0.0),
            -int(r.get("trades_removed") or 0),
        ),
        reverse=True,
    )[: max(1, int(SWING_TUNING_SIM_MAX_CANDIDATES or 12))]
    best = scenarios[0] if scenarios else {}
    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "read_only_simulation",
        "baseline": baseline,
        "best_tuning_candidate": best,
        "scenarios": scenarios,
        "scenario_count": len(scenarios),
        "recommended_action": "review_best_candidate_before_live_filter" if scenarios else "collect_more_closed_trades",
        "config": {
            "max_candidates": int(SWING_TUNING_SIM_MAX_CANDIDATES or 0),
            "min_removed_trades": int(SWING_TUNING_SIM_MIN_REMOVED_TRADES or 0),
            "read_only": True,
        },
    }


def _p211_is_stall_exit(row: dict | None) -> bool:
    return _p207_closed_trade_exit_reason(row) == "stall_exit"


def _p211_simulate_stall_tightening(all_rows: list[dict], stall_rows: list[dict], name: str, removed_rows: list[dict], rationale: str, env_hint: str) -> dict:
    removed_ids = {id(r) for r in removed_rows}
    kept = [r for r in all_rows if id(r) not in removed_ids]
    baseline = _p210_rows_summary(all_rows)
    after = _p210_rows_summary(kept)
    removed = _p210_rows_summary(removed_rows)
    base_totals = _p210_safe_dict(baseline.get("totals"))
    after_totals = _p210_safe_dict(after.get("totals"))
    after_risk = _p210_safe_dict(after.get("risk_scaling"))
    return {
        "name": name,
        "rationale": rationale,
        "env_hint": env_hint,
        "trades_removed": len(removed_rows),
        "stall_trades_removed": len([r for r in removed_rows if _p211_is_stall_exit(r)]),
        "removed_gross_pnl": round(float(_p210_safe_dict(removed.get("totals")).get("gross_pnl") or 0.0), 4),
        "removed_avg_r": _p210_safe_dict(removed.get("totals")).get("avg_r"),
        "simulated_gross_pnl": round(float(after_totals.get("gross_pnl") or 0.0), 4),
        "gross_pnl_delta": round(float(after_totals.get("gross_pnl") or 0.0) - float(base_totals.get("gross_pnl") or 0.0), 4),
        "simulated_avg_r": after_totals.get("avg_r"),
        "avg_r_delta": round(float(after_totals.get("avg_r") or 0.0) - float(base_totals.get("avg_r") or 0.0), 4),
        "simulated_worst_r": after_totals.get("worst_r"),
        "ready_for_40_risk_after": bool(after_risk.get("ready_for_40_risk")),
        "ready_for_50_risk_after": bool(after_risk.get("ready_for_50_risk")),
        "risk_blockers_after": list(after_risk.get("blockers") or []),
    }


def _swing_stall_exit_drilldown(perf_state: dict | None = None) -> dict:
    state = perf_state if isinstance(perf_state, dict) else _recompute_strategy_performance_state()
    state, _ = _patch175_enrich_state_if_needed(state)
    rows = [dict(r) for r in list((state or {}).get("closed_trades") or []) if isinstance(r, dict)]
    stall_rows = [r for r in rows if _p211_is_stall_exit(r)]
    baseline = _p210_rows_summary(rows)
    stall_summary = _p210_rows_summary(stall_rows)
    current_stall_days = int(SWING_STALL_EXIT_DAYS or 0)
    current_stall_min_r = float(SWING_STALL_MIN_R or 0.0)

    negative_stalls = [r for r in stall_rows if (_p175_closed_trade_r(r) is not None and float(_p175_closed_trade_r(r) or 0.0) < 0)]
    deep_stalls = [r for r in stall_rows if (_p175_closed_trade_r(r) is not None and float(_p175_closed_trade_r(r) or 0.0) <= -1.0)]
    guard_leak_stalls = [r for r in stall_rows if (_p175_closed_trade_r(r) is not None and float(_p175_closed_trade_r(r) or 0.0) <= float(SWING_STALL_MAX_LOSS_R or -0.60))]
    slow_stalls = [r for r in stall_rows if ((_p175_holding_days(r) or 0.0) >= max(1, current_stall_days + 1))]
    low_rank_stalls = [r for r in stall_rows if (_p175_rank_score(r) is not None and float(_p175_rank_score(r) or 0.0) < 80.0)]
    weak_regime_stalls = [r for r in stall_rows if str(_p175_first(r, "entry_regime_mode", "regime_mode", "regime") or "unknown").strip().lower() not in {"trend", "favorable", "bull", "strong"}]

    simulations = [
        _p211_simulate_stall_tightening(rows, stall_rows, "stall_loss_guard_for_guard_leaks", guard_leak_stalls, "Exit stalled trades before they can compound into deep loss-R outliers.", "set_SWING_STALL_LOSS_GUARD_ENABLED_true_and_SWING_STALL_MAX_LOSS_R"),
        _p211_simulate_stall_tightening(rows, stall_rows, "raise_stall_min_r_filter_negative_stalls", negative_stalls, "Do not let stalled trades remain open once they are below 0R at the stall check.", "consider_raising_SWING_STALL_MIN_R"),
        _p211_simulate_stall_tightening(rows, stall_rows, "earlier_break_even_for_deep_stalls", deep_stalls, "Focus on stall exits that became worse than -1R; these are the tail-risk stall failures.", "consider_lowering_SWING_BREAK_EVEN_R_or_tightening_stops"),
        _p211_simulate_stall_tightening(rows, stall_rows, "reduce_stall_exit_days_for_slow_stalls", slow_stalls, "Model exiting slow stalled trades before they remain open beyond the current stall window.", "consider_lowering_SWING_STALL_EXIT_DAYS"),
        _p211_simulate_stall_tightening(rows, stall_rows, "require_rank_80_for_stall_prone_entries", low_rank_stalls, "Model avoiding stall-prone entries with rank score below 80.", "consider_raising_rank_floor_for_stall_prone_setups"),
        _p211_simulate_stall_tightening(rows, stall_rows, "avoid_weak_regime_stall_setups", weak_regime_stalls, "Model avoiding stall-prone entries outside favorable/trend regimes.", "consider_tightening_regime_filter_for_stall_prone_setups"),
    ]
    simulations = [s for s in simulations if int(s.get("trades_removed") or 0) > 0]
    simulations = sorted(simulations, key=lambda r: (float(r.get("gross_pnl_delta") or 0.0), float(r.get("avg_r_delta") or 0.0), bool(r.get("ready_for_40_risk_after"))), reverse=True)
    best = simulations[0] if simulations else {}
    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "read_only_drilldown",
        "baseline": baseline,
        "stall_exit_summary": stall_summary.get("totals"),
        "by_symbol": _p207_bucket_summary(stall_rows, lambda r: str(r.get("symbol") or "unknown").upper() or "unknown"),
        "by_holding_period": _p207_bucket_summary(stall_rows, _p175_holding_bucket),
        "by_regime_mode": _p207_bucket_summary(stall_rows, lambda r: str(_p175_first(r, "entry_regime_mode", "regime_mode", "regime") or "unknown").strip().lower() or "unknown"),
        "by_rank_bucket": _p207_bucket_summary(stall_rows, _p175_rank_bucket),
        "by_strategy": _p207_bucket_summary(stall_rows, _p207_closed_trade_strategy),
        "worst_stall_trades": _p208_worst_trade_contributors(stall_rows, limit=10),
        "exit_tightening_simulations": simulations,
        "recommended_exit_tuning": best,
        "config": {
            "current_SWING_STALL_EXIT_DAYS": current_stall_days,
            "current_SWING_STALL_MIN_R": current_stall_min_r,
            "SWING_STALL_LOSS_GUARD_ENABLED": bool(SWING_STALL_LOSS_GUARD_ENABLED),
            "SWING_STALL_LOSS_GUARD_DAYS": int(SWING_STALL_LOSS_GUARD_DAYS or 0),
            "SWING_STALL_MAX_LOSS_R": float(SWING_STALL_MAX_LOSS_R or 0.0),
            "read_only": True,
        },
    }

def _p256_broker_preferred_rows_for_stall() -> list[dict]:
    preferred = _p245_broker_preferred_closed_rows()
    rows = [dict(r or {}) for r in list(preferred.get("kept_rows") or []) if isinstance(r, dict)]
    return rows


def _p256_stall_exit_rows(rows: list[dict]) -> list[dict]:
    return [dict(r or {}) for r in rows if _p211_is_stall_exit(r)]


def _p256_stall_profit_leak_row(row: dict | None) -> dict:
    r = dict(row or {})
    pnl_r = _p175_closed_trade_r(r)
    gross = _p175_closed_trade_pnl(r)
    holding_days = _p175_holding_days(r)
    rank = _p175_rank_score(r)
    return {
        "symbol": str(r.get("symbol") or "").upper(),
        "strategy": _p207_closed_trade_strategy(r),
        "entry_type": _p207_closed_trade_entry_type(r),
        "exit_reason": _p207_closed_trade_exit_reason(r),
        "gross_pnl": round(gross, 4),
        "pnl_r": pnl_r,
        "holding_days": holding_days,
        "rank_score": rank,
        "rank_bucket": _p175_rank_bucket(r),
        "holding_bucket": _p175_holding_bucket(r),
        "regime_mode": str(_p175_first(r, "entry_regime_mode", "regime_mode", "regime") or "unknown").strip().lower() or "unknown",
        "entry_ts_utc": _p175_first(r, "entry_ts_utc", "opened_at"),
        "exit_ts_utc": _p175_first(r, "ts_utc", "exit_ts_utc", "closed_at", "updated_at"),
        "source": r.get("source"),
        "broker_reconciled": bool(r.get("broker_reconciled")) or str(r.get("source") or "").strip().lower() == "alpaca_orders_reconciled",
        "leak_class": (
            "deep_loss_stall" if pnl_r is not None and float(pnl_r) <= -1.0 else
            "guard_threshold_loss" if pnl_r is not None and float(pnl_r) <= float(SWING_STALL_MAX_LOSS_R or -0.60) else
            "negative_stall" if pnl_r is not None and float(pnl_r) < 0 else
            "positive_or_flat_stall"
        ),
    }


def _p256_rows_summary(rows: list[dict]) -> dict:
    totals = _p210_safe_dict(_p210_rows_summary(rows).get("totals"))
    return {
        "closed_trades": int(totals.get("closed_trades") or 0),
        "wins": int(totals.get("wins") or 0),
        "losses": int(totals.get("losses") or 0),
        "win_rate": totals.get("win_rate"),
        "gross_pnl": totals.get("gross_pnl"),
        "avg_r": totals.get("avg_r"),
        "worst_r": totals.get("worst_r"),
        "best_r": totals.get("best_r"),
    }


def _p256_row_fingerprint(row: dict | None) -> str:
    r = dict(row or {})
    return "|".join([
        str(r.get("symbol") or "").upper(),
        _p207_closed_trade_strategy(r),
        _p207_closed_trade_exit_reason(r),
        str(_p175_first(r, "entry_ts_utc", "opened_at") or ""),
        str(_p175_first(r, "ts_utc", "exit_ts_utc", "closed_at", "updated_at") or ""),
        str(r.get("entry_order_id") or ""),
        str(r.get("exit_order_id") or ""),
        str(round(_safe_float(r.get("qty"), 0.0), 6)),
        str(round(_safe_float(r.get("entry_price"), 0.0), 6)),
        str(round(_safe_float(r.get("exit_price"), 0.0), 6)),
        str(round(_safe_float(r.get("gross_pnl"), 0.0), 6)),
        str(round(_safe_float(r.get("pnl_r"), 0.0), 6)),
    ])


def _p256_apply_loss_cap_to_row(row: dict | None, cap_r: float) -> tuple[dict, bool]:
    r = dict(row or {})
    pnl_r = _p175_closed_trade_r(r)
    gross = _p175_closed_trade_pnl(r)

    if pnl_r is None:
        return r, False

    pnl_r = float(pnl_r)
    cap_r = float(cap_r)

    if pnl_r >= cap_r:
        return r, False

    if abs(pnl_r) <= 1e-9:
        return r, False

    risk_dollars = abs(float(gross) / pnl_r)
    if risk_dollars <= 0:
        return r, False

    capped_gross = round(risk_dollars * cap_r, 4)
    capped_r = round(cap_r, 4)

    r["p256_original_gross_pnl"] = round(float(gross), 4)
    r["p256_original_pnl_r"] = round(pnl_r, 4)
    r["p256_loss_cap_r"] = capped_r
    r["p256_repriced"] = True
    r["gross_pnl"] = capped_gross
    r["pnl_r"] = capped_r
    return r, True


def _p256_reprice_rows_with_loss_cap(all_rows: list[dict], affected_rows: list[dict], cap_r: float) -> tuple[list[dict], list[dict]]:
    affected_keys = {_p256_row_fingerprint(r) for r in affected_rows}
    repriced_rows = []
    changed_rows = []

    for row in all_rows:
        r = dict(row or {})
        if _p256_row_fingerprint(r) in affected_keys:
            adjusted, changed = _p256_apply_loss_cap_to_row(r, cap_r)
            repriced_rows.append(adjusted)
            if changed:
                changed_rows.append(adjusted)
        else:
            repriced_rows.append(r)

    return repriced_rows, changed_rows


def _p256_conservative_stall_retune_scenario(
    all_rows: list[dict],
    affected_rows: list[dict],
    name: str,
    rationale: str,
    env_hint: str,
    confidence: str,
    cap_r: float,
) -> dict:
    simulated_rows, changed_rows = _p256_reprice_rows_with_loss_cap(all_rows, affected_rows, cap_r)
    baseline = _p256_rows_summary(all_rows)
    simulated = _p256_rows_summary(simulated_rows)
    affected = _p256_rows_summary(affected_rows)
    changed = _p256_rows_summary(changed_rows)

    baseline_pnl = _safe_float(baseline.get("gross_pnl"), 0.0)
    simulated_pnl = _safe_float(simulated.get("gross_pnl"), 0.0)

    return {
        "scenario": name,
        "rationale": rationale,
        "env_hint": env_hint,
        "confidence": confidence,
        "loss_cap_r": round(float(cap_r), 4),
        "affected_count": len(affected_rows),
        "repriced_count": len(changed_rows),
        "affected_symbols": sorted({str(r.get("symbol") or "").upper() for r in affected_rows if str(r.get("symbol") or "").strip()}),
        "affected": affected,
        "repriced": changed,
        "simulated": simulated,
        "gross_pnl_delta": round(simulated_pnl - baseline_pnl, 4),
        "avg_r_delta": round(_safe_float(simulated.get("avg_r"), 0.0) - _safe_float(baseline.get("avg_r"), 0.0), 4),
        "win_rate_delta": round(_safe_float(simulated.get("win_rate"), 0.0) - _safe_float(baseline.get("win_rate"), 0.0), 4),
        "repriced_rows": [
            {
                "symbol": str(r.get("symbol") or "").upper(),
                "original_gross_pnl": r.get("p256_original_gross_pnl"),
                "repriced_gross_pnl": r.get("gross_pnl"),
                "original_pnl_r": r.get("p256_original_pnl_r"),
                "repriced_pnl_r": r.get("pnl_r"),
                "loss_cap_r": r.get("p256_loss_cap_r"),
                "exit_reason": _p207_closed_trade_exit_reason(r),
                "ts_utc": _p175_first(r, "ts_utc", "exit_ts_utc", "closed_at", "updated_at"),
            }
            for r in changed_rows[:25]
        ],
        "note": "Closed-trade proxy only. This reprices historical affected stall exits to a loss cap and does not prove the exact alternative live fill price.",
    }

def _p256_stall_exit_profit_leak_drilldown() -> dict:
    rows = _p256_broker_preferred_rows_for_stall()
    stall_rows = _p256_stall_exit_rows(rows)
    stall_detail = [_p256_stall_profit_leak_row(r) for r in stall_rows]

    negative_stalls = [r for r in stall_rows if (_p175_closed_trade_r(r) is not None and float(_p175_closed_trade_r(r) or 0.0) < 0)]
    guard_threshold_stalls = [r for r in stall_rows if (_p175_closed_trade_r(r) is not None and float(_p175_closed_trade_r(r) or 0.0) <= float(SWING_STALL_MAX_LOSS_R or -0.60))]
    deep_loss_stalls = [r for r in stall_rows if (_p175_closed_trade_r(r) is not None and float(_p175_closed_trade_r(r) or 0.0) <= -1.0)]
    slow_negative_stalls = [
        r for r in stall_rows
        if (_p175_closed_trade_r(r) is not None and float(_p175_closed_trade_r(r) or 0.0) < 0)
        and ((_p175_holding_days(r) or 0.0) >= max(1, int(SWING_STALL_EXIT_DAYS or 0)))
    ]
    low_rank_negative_stalls = [
        r for r in negative_stalls
        if (_p175_rank_score(r) is not None and float(_p175_rank_score(r) or 0.0) < 88.0)
    ]
    weak_regime_negative_stalls = [
        r for r in negative_stalls
        if str(_p175_first(r, "entry_regime_mode", "regime_mode", "regime") or "unknown").strip().lower() not in {"trend", "favorable", "bull", "strong"}
    ]

    scenarios = [
        _p256_conservative_stall_retune_scenario(
            rows,
            guard_threshold_stalls,
            "cap_guard_threshold_stalls_at_minus_0_60r",
            "Models the current stall loss guard working as a hard cap at -0.60R for trades that leaked beyond it.",
            "confirm_SWING_STALL_LOSS_GUARD_ENABLED=true_and_SWING_STALL_MAX_LOSS_R=-0.60",
            "medium",
            -0.60,
        ),
        _p256_conservative_stall_retune_scenario(
            rows,
            guard_threshold_stalls,
            "tighten_stall_loss_guard_to_minus_0_40r",
            "Models a more conservative stall loss guard cap at -0.40R for trades that leaked beyond the current guard threshold.",
            "consider_SWING_STALL_MAX_LOSS_R=-0.40_after_review",
            "medium",
            -0.40,
        ),
        _p256_conservative_stall_retune_scenario(
            rows,
            deep_loss_stalls,
            "cap_deep_stall_tail_at_minus_1_00r",
            "Models preventing only the deepest stall-exit tail losses from exceeding -1.00R.",
            "review_break_even_and_stop_tightening_for_stall_prone_positions",
            "medium",
            -1.00,
        ),
        _p256_conservative_stall_retune_scenario(
            rows,
            slow_negative_stalls,
            "cap_slow_negative_stalls_at_minus_0_50r",
            "Models earlier plain-stall action for negative slow stalls by capping them at -0.50R.",
            "consider_SWING_STALL_EXIT_DAYS=2_only_if_live_sample_confirms",
            "low_to_medium",
            -0.50,
        ),
        _p256_conservative_stall_retune_scenario(
            rows,
            low_rank_negative_stalls,
            "cap_low_rank_negative_stalls_at_minus_0_50r",
            "Models entry-quality protection for lower-rank entries that later became negative stall exits.",
            "consider_entry_quality_guard_for_rank_below_88_after_review",
            "medium",
            -0.50,
        ),
        _p256_conservative_stall_retune_scenario(
            rows,
            weak_regime_negative_stalls,
            "cap_weak_regime_negative_stalls_at_minus_0_50r",
            "Models tighter regime protection for trades that later became negative stall exits.",
            "consider_tighter_regime_filter_for_stall_prone_entries_after_review",
            "medium",
            -0.50,
        ),
    ]
    scenarios = [s for s in scenarios if int(s.get("affected_count") or 0) > 0 and int(s.get("repriced_count") or 0) > 0]
    scenarios.sort(
        key=lambda r: (
            _safe_float(r.get("gross_pnl_delta"), 0.0),
            _safe_float(r.get("avg_r_delta"), 0.0),
            _safe_float(r.get("win_rate_delta"), 0.0),
        ),
        reverse=True,
    )

    baseline = _p256_rows_summary(rows)
    stall_summary = _p256_rows_summary(stall_rows)
    negative_summary = _p256_rows_summary(negative_stalls)
    best = scenarios[0] if scenarios else {}

    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "read_only_stall_exit_profit_leak_drilldown",
        "baseline": baseline,
        "stall_exit_summary": stall_summary,
        "negative_stall_summary": negative_summary,
        "profit_leak": {
            "stall_exit_count": len(stall_rows),
            "negative_stall_count": len(negative_stalls),
            "guard_threshold_stall_gross_pnl": round(sum(_p175_closed_trade_pnl(r) for r in guard_threshold_stalls), 4),
            "deep_loss_stall_gross_pnl": round(sum(_p175_closed_trade_pnl(r) for r in deep_loss_stalls), 4),
            "guard_threshold_stall_count": len(guard_threshold_stalls),
            "deep_loss_stall_count": len(deep_loss_stalls),
            "stall_exit_gross_pnl": stall_summary.get("gross_pnl"),
            "negative_stall_gross_pnl": negative_summary.get("gross_pnl"),
            "stall_share_of_closed_trades": round(len(stall_rows) / max(1, len(rows)), 4),
            "negative_stall_share_of_stalls": round(len(negative_stalls) / max(1, len(stall_rows)), 4),
        },
        "by_symbol": _p207_bucket_summary(stall_rows, lambda r: str(r.get("symbol") or "unknown").upper() or "unknown"),
        "by_holding_period": _p207_bucket_summary(stall_rows, _p175_holding_bucket),
        "by_regime_mode": _p207_bucket_summary(stall_rows, lambda r: str(_p175_first(r, "entry_regime_mode", "regime_mode", "regime") or "unknown").strip().lower() or "unknown"),
        "by_rank_bucket": _p207_bucket_summary(stall_rows, _p175_rank_bucket),
        "worst_stall_trades": sorted(stall_detail, key=lambda r: (_safe_float(r.get("pnl_r"), 0.0), _safe_float(r.get("gross_pnl"), 0.0)))[:10],
        "conservative_retune_simulations": scenarios,
        "best_conservative_retune": best,
        "recommended_action": "review_best_conservative_retune_before_env_change" if scenarios else "collect_more_stall_exit_sample",
        "config": {
            "current_SWING_STALL_EXIT_DAYS": int(SWING_STALL_EXIT_DAYS or 0),
            "current_SWING_STALL_MIN_R": float(SWING_STALL_MIN_R or 0.0),
            "SWING_STALL_LOSS_GUARD_ENABLED": bool(SWING_STALL_LOSS_GUARD_ENABLED),
            "SWING_STALL_LOSS_GUARD_DAYS": int(SWING_STALL_LOSS_GUARD_DAYS or 0),
            "SWING_STALL_MAX_LOSS_R": float(SWING_STALL_MAX_LOSS_R or 0.0),
            "read_only": True,
        },
    }

def _p212_closed_trade_ts(row: dict | None):
    row = row if isinstance(row, dict) else {}
    return _p175_parse_dt(_p175_first(row, "ts_utc", "exit_ts_utc", "closed_at", "updated_at", "exit_time"))


def _p212_rows_since(rows: list[dict], start_utc: str = "") -> list[dict]:
    start_dt = _p175_parse_dt(start_utc) if start_utc else None
    if not start_dt:
        return list(rows or [])
    out = []
    for row in rows or []:
        ts = _p212_closed_trade_ts(row)
        if ts and ts >= start_dt:
            out.append(row)
    return out

def _p261_exit_reason(row: dict | None) -> str:
    row = dict(row or {})
    return str(
        row.get("attributed_exit_reason")
        or row.get("exit_reason")
        or row.get("reason")
        or "unknown"
    ).strip().lower() or "unknown"


def _p261_is_stall_family_exit(row: dict | None) -> bool:
    return _p261_exit_reason(row) in {"stall_exit", "stall_loss_guard"}


def _p261_broker_preferred_attributed_rows(
    perf_state: dict | None = None,
) -> dict:
    preferred = _p245_broker_preferred_closed_rows(
        state=perf_state if isinstance(perf_state, dict) else None
    )
    kept_rows = [
        dict(row)
        for row in list(preferred.get("kept_rows") or [])
        if isinstance(row, dict)
    ]
    shadowed_rows = [
        dict(row)
        for row in list(preferred.get("shadowed_rows") or [])
        if isinstance(row, dict)
    ]

    shadowed_by_key: dict[str, list[dict]] = {}
    for row in shadowed_rows:
        key = _p244_exit_audit_session_key(row)
        shadowed_by_key.setdefault(key, []).append(row)

    attributed_rows = []
    attribution_count = 0

    for raw in kept_rows:
        row = dict(raw)
        key = _p244_exit_audit_session_key(row)
        worker_matches = shadowed_by_key.get(key) or []
        worker_row = worker_matches[-1] if worker_matches else {}

        if _p245_is_broker_reconciled_exit(row) and worker_row:
            attributed_reason = str(
                worker_row.get("exit_reason")
                or worker_row.get("reason")
                or ""
            ).strip().lower()

            if attributed_reason:
                row["attributed_exit_reason"] = attributed_reason
                row["broker_exit_reason"] = str(
                    row.get("exit_reason")
                    or row.get("reason")
                    or "broker_exit_fill"
                ).strip().lower()
                row["attribution_source"] = "paired_worker_exit"
                attribution_count += 1

            worker_r = _p175_closed_trade_r(worker_row)
            if worker_r is not None:
                row["attributed_pnl_r"] = round(float(worker_r), 4)
                row["pnl_r"] = round(float(worker_r), 4)

            for field in (
                "entry_ts_utc",
                "entry_regime_mode",
                "regime_mode",
                "rank_score",
                "selection_quality_score",
                "entry_type",
                "holding_hours",
                "holding_days",
                "breakout_level",
                "recovered",
            ):
                if row.get(field) in (None, "") and worker_row.get(field) not in (None, ""):
                    row[field] = worker_row.get(field)

        row["exit_reason_family"] = (
            "stall_family" if _p261_is_stall_family_exit(row) else "other"
        )
        attributed_rows.append(row)

    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "source": "broker_preferred_with_worker_decision_attribution",
        "raw_count": preferred.get("raw_count"),
        "kept_count": len(attributed_rows),
        "shadowed_worker_count": preferred.get("shadowed_worker_count"),
        "attributed_exit_count": attribution_count,
        "rows": attributed_rows,
    }


def _p261_cohort_summary(rows: list[dict] | None) -> dict:
    rows = [dict(row) for row in list(rows or []) if isinstance(row, dict)]
    summary = _p210_rows_summary(rows).get("totals") or {}

    return {
        "closed_trades": int(summary.get("closed_trades") or 0),
        "wins": int(summary.get("wins") or 0),
        "losses": int(summary.get("losses") or 0),
        "flat": int(summary.get("flat") or 0),
        "win_rate": round(float(summary.get("win_rate") or 0.0), 4),
        "gross_pnl": round(float(summary.get("gross_pnl") or 0.0), 4),
        "avg_r": round(float(summary.get("avg_r") or 0.0), 4),
        "worst_r": summary.get("worst_r"),
        "best_r": summary.get("best_r"),
    }


def _p261_bucket_summaries(rows: list[dict], field_fn) -> list[dict]:
    buckets: dict[str, list[dict]] = {}

    for row in rows:
        key = str(field_fn(row) or "unknown").strip() or "unknown"
        buckets.setdefault(key, []).append(row)

    output = []
    for key, bucket_rows in buckets.items():
        output.append({
            "key": key,
            **_p261_cohort_summary(bucket_rows),
        })

    return sorted(
        output,
        key=lambda item: (
            float(item.get("gross_pnl") or 0.0),
            -int(item.get("closed_trades") or 0),
        ),
    )


def _p261_post_change_drawdown_snapshot(
    perf_state: dict | None = None,
) -> dict:
    start_utc = str(SWING_STALL_TUNING_START_UTC or "").strip()
    start_dt = _p175_parse_dt(start_utc) if start_utc else None
    attributed = _p261_broker_preferred_attributed_rows(perf_state=perf_state)
    all_rows = list(attributed.get("rows") or [])
    post_rows = _p212_rows_since(all_rows, start_utc) if start_dt else []

    guarded_strategies = set(SWING_POST_CHANGE_DRAWDOWN_GUARD_STRATEGIES)
    guarded_rows = [
        row
        for row in post_rows
        if str(
            row.get("strategy_name")
            or row.get("signal")
            or "unknown"
        ).strip().lower() in guarded_strategies
    ]
    stall_family_rows = [
        row for row in guarded_rows if _p261_is_stall_family_exit(row)
    ]

    totals = _p261_cohort_summary(guarded_rows)
    stall_totals = _p261_cohort_summary(stall_family_rows)
    closed_trades = int(totals.get("closed_trades") or 0)
    win_rate = float(totals.get("win_rate") or 0.0)
    avg_r = float(totals.get("avg_r") or 0.0)
    gross_pnl = float(totals.get("gross_pnl") or 0.0)

    trigger_reasons = []
    if closed_trades < int(SWING_POST_CHANGE_DRAWDOWN_MIN_TRADES):
        trigger_reasons.append("sample_below_minimum")
    if win_rate > float(SWING_POST_CHANGE_DRAWDOWN_MAX_WIN_RATE):
        trigger_reasons.append("win_rate_above_drawdown_trigger")
    if avg_r > float(SWING_POST_CHANGE_DRAWDOWN_MAX_AVG_R):
        trigger_reasons.append("avg_r_above_drawdown_trigger")
    if gross_pnl >= 0:
        trigger_reasons.append("gross_pnl_not_negative")

    triggered = bool(
        SWING_POST_CHANGE_DRAWDOWN_GUARD_ENABLED
        and start_dt
        and closed_trades >= int(SWING_POST_CHANGE_DRAWDOWN_MIN_TRADES)
        and win_rate <= float(SWING_POST_CHANGE_DRAWDOWN_MAX_WIN_RATE)
        and avg_r <= float(SWING_POST_CHANGE_DRAWDOWN_MAX_AVG_R)
        and gross_pnl < 0
    )
    block_new_entries = bool(
        triggered
        and SWING_POST_CHANGE_DRAWDOWN_BLOCK_NEW_ENTRIES
        and not SWING_POST_CHANGE_DRAWDOWN_ADVISORY_ONLY
    )

    if triggered:
        recommended_action = "rollback_recent_daily_breakout_entry_cohort"
    elif not start_dt:
        recommended_action = "configure_post_change_start_utc"
    else:
        recommended_action = "continue_monitoring"

    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "swing_post_change_drawdown_circuit",
        "enabled": bool(SWING_POST_CHANGE_DRAWDOWN_GUARD_ENABLED),
        "advisory_only": bool(SWING_POST_CHANGE_DRAWDOWN_ADVISORY_ONLY),
        "post_change_start_utc": start_utc,
        "post_change_window_configured": bool(start_dt),
        "guarded_strategies": sorted(guarded_strategies),
        "triggered": triggered,
        "block_new_entries": block_new_entries,
        "exits_still_permitted": True,
        "unaffected_strategies": ["daily_mean_reversion"],
        "trigger_reasons": [] if triggered else trigger_reasons,
        "totals": totals,
        "stall_family_totals": stall_totals,
        "stall_exit_count": sum(
            1 for row in stall_family_rows
            if _p261_exit_reason(row) == "stall_exit"
        ),
        "stall_loss_guard_count": sum(
            1 for row in stall_family_rows
            if _p261_exit_reason(row) == "stall_loss_guard"
        ),
        "by_exit_reason": _p261_bucket_summaries(
            guarded_rows,
            _p261_exit_reason,
        ),
        "by_entry_date": _p261_bucket_summaries(
            guarded_rows,
            lambda row: str(row.get("entry_ts_utc") or "unknown")[:10],
        ),
        "by_regime": _p261_bucket_summaries(
            guarded_rows,
            lambda row: row.get("entry_regime_mode")
            or row.get("regime_mode")
            or "unknown",
        ),
        "by_entry_type": _p261_bucket_summaries(
            guarded_rows,
            lambda row: row.get("entry_type") or "unknown",
        ),
        "by_recovery_status": _p261_bucket_summaries(
            guarded_rows,
            lambda row: "recovered" if row.get("recovered") else "native",
        ),
        "recent_rows": guarded_rows[-25:],
        "criteria": {
            "min_closed_trades": int(SWING_POST_CHANGE_DRAWDOWN_MIN_TRADES),
            "max_win_rate": float(SWING_POST_CHANGE_DRAWDOWN_MAX_WIN_RATE),
            "max_avg_r": float(SWING_POST_CHANGE_DRAWDOWN_MAX_AVG_R),
            "gross_pnl_must_be_negative": True,
        },
        "recommended_action": recommended_action,
    }


def _p261_strategy_entry_block(strategy: str) -> dict:
    normalized = str(strategy or "").strip().lower()
    circuit = _p261_post_change_drawdown_snapshot()

    blocked = bool(
        circuit.get("block_new_entries")
        and normalized in set(circuit.get("guarded_strategies") or [])
    )

    return {
        "blocked": blocked,
        "reason": "swing_post_change_drawdown_circuit" if blocked else "none",
        "strategy": normalized,
        "circuit": circuit,
    }

def _p262_entry_dt(row: dict | None):
    row = dict(row or {})
    return _p175_parse_dt(
        row.get("entry_ts_utc")
        or row.get("opened_at")
        or row.get("entry_time")
    )


def _p262_strategy(row: dict | None) -> str:
    row = dict(row or {})
    return str(
        row.get("strategy_name")
        or row.get("signal")
        or "unknown"
    ).strip().lower() or "unknown"


def _p262_rank(row: dict | None):
    row = dict(row or {})
    value = row.get("rank_score")
    if value in (None, ""):
        return None
    try:
        return float(value)
    except Exception:
        return None


def _p262_regime(row: dict | None) -> str:
    row = dict(row or {})
    return str(
        row.get("entry_regime_mode")
        or row.get("regime_mode")
        or "unknown"
    ).strip().lower() or "unknown"


def _p262_entry_type(row: dict | None) -> str:
    row = dict(row or {})
    return str(
        row.get("entry_type")
        or "unknown"
    ).strip().lower() or "unknown"


def _p262_split_entry_cohorts(
    rows: list[dict],
    start_dt,
    pre_limit: int,
) -> tuple[list[dict], list[dict], list[dict]]:
    rows_with_entry = [
        dict(row)
        for row in list(rows or [])
        if _p262_entry_dt(row) is not None
    ]
    rows_with_entry.sort(
        key=lambda row: _p262_entry_dt(row)
    )

    pre_rows = [
        row for row in rows_with_entry
        if _p262_entry_dt(row) < start_dt
    ]
    post_rows = [
        row for row in rows_with_entry
        if _p262_entry_dt(row) >= start_dt
    ]
    pre_window = pre_rows[-max(1, int(pre_limit or 30)):]

    carried_into_post_window = []
    for row in pre_rows:
        close_dt = _p212_closed_trade_ts(row)
        if close_dt and close_dt >= start_dt:
            carried_into_post_window.append(row)

    return pre_window, post_rows, carried_into_post_window


def _p262_attribute_coverage(rows: list[dict]) -> dict:
    rows = [dict(row) for row in list(rows or [])]
    count = len(rows)

    def coverage(present_count: int) -> float:
        return round(present_count / max(1, count), 4) if count else 0.0

    rank_count = sum(1 for row in rows if _p262_rank(row) is not None)
    regime_count = sum(
        1 for row in rows if _p262_regime(row) != "unknown"
    )
    entry_type_count = sum(
        1 for row in rows if _p262_entry_type(row) != "unknown"
    )
    entry_ts_count = sum(
        1 for row in rows if _p262_entry_dt(row) is not None
    )

    return {
        "row_count": count,
        "entry_ts_count": entry_ts_count,
        "entry_ts_coverage": coverage(entry_ts_count),
        "rank_count": rank_count,
        "rank_coverage": coverage(rank_count),
        "regime_count": regime_count,
        "regime_coverage": coverage(regime_count),
        "entry_type_count": entry_type_count,
        "entry_type_coverage": coverage(entry_type_count),
    }


def _p262_filter_scenario(
    name: str,
    rows: list[dict],
    start_dt,
    pre_limit: int,
    keep_fn,
    rationale: str,
    env_hint: str = "",
    required_attribute: str = "",
) -> dict:
    baseline_rows = [dict(row) for row in list(rows or [])]
    kept_rows = []
    removed_rows = []

    for row in baseline_rows:
        if keep_fn(row):
            kept_rows.append(row)
        else:
            removed_rows.append(row)

    base_pre, base_post, _ = _p262_split_entry_cohorts(
        baseline_rows,
        start_dt,
        pre_limit,
    )
    kept_pre, kept_post, _ = _p262_split_entry_cohorts(
        kept_rows,
        start_dt,
        pre_limit,
    )

    base_pre_summary = _p261_cohort_summary(base_pre)
    base_post_summary = _p261_cohort_summary(base_post)
    simulated_pre = _p261_cohort_summary(kept_pre)
    simulated_post = _p261_cohort_summary(kept_post)

    removed_pre = [
        row for row in removed_rows
        if _p262_entry_dt(row)
        and _p262_entry_dt(row) < start_dt
    ]
    removed_post = [
        row for row in removed_rows
        if _p262_entry_dt(row)
        and _p262_entry_dt(row) >= start_dt
    ]

    return {
        "scenario": name,
        "rationale": rationale,
        "env_hint": env_hint,
        "required_attribute": required_attribute or None,
        "base_pre": base_pre_summary,
        "base_post": base_post_summary,
        "simulated_pre": simulated_pre,
        "simulated_post": simulated_post,
        "removed_pre_count": len(removed_pre),
        "removed_post_count": len(removed_post),
        "removed_pre": _p261_cohort_summary(removed_pre),
        "removed_post": _p261_cohort_summary(removed_post),
        "pre_gross_pnl_delta": round(
            _safe_float(simulated_pre.get("gross_pnl"), 0.0)
            - _safe_float(base_pre_summary.get("gross_pnl"), 0.0),
            4,
        ),
        "post_gross_pnl_delta": round(
            _safe_float(simulated_post.get("gross_pnl"), 0.0)
            - _safe_float(base_post_summary.get("gross_pnl"), 0.0),
            4,
        ),
        "pre_avg_r_delta": round(
            _safe_float(simulated_pre.get("avg_r"), 0.0)
            - _safe_float(base_pre_summary.get("avg_r"), 0.0),
            4,
        ),
        "post_avg_r_delta": round(
            _safe_float(simulated_post.get("avg_r"), 0.0)
            - _safe_float(base_post_summary.get("avg_r"), 0.0),
            4,
        ),
        "removed_symbols": sorted({
            str(row.get("symbol") or "").upper()
            for row in removed_rows
            if str(row.get("symbol") or "").strip()
        }),
    }


def _p262_daily_cap_scenario(
    name: str,
    rows: list[dict],
    start_dt,
    pre_limit: int,
    cap: int,
) -> dict:
    kept_rows, removed_rows = _p255_filter_daily_entry_cap(rows, cap)

    kept_ids = {
        id(row) for row in kept_rows
    }
    removed_fingerprints = {
        (
            str(row.get("symbol") or ""),
            str(
                row.get("entry_ts_utc")
                or row.get("opened_at")
                or row.get("ts_utc")
                or ""
            ),
        )
        for row in removed_rows
    }

    return _p262_filter_scenario(
        name=name,
        rows=rows,
        start_dt=start_dt,
        pre_limit=pre_limit,
        keep_fn=lambda row: (
            (
                str(row.get("symbol") or ""),
                str(
                    row.get("entry_ts_utc")
                    or row.get("opened_at")
                    or row.get("ts_utc")
                    or ""
                ),
            )
            not in removed_fingerprints
        ),
        rationale=(
            f"Closed-trade proxy limiting daily breakout entries "
            f"to {int(cap)} per NY trading day."
        ),
        env_hint=f"SWING_MAX_NEW_ENTRIES_PER_DAY={int(cap)}",
    )


def _p262_daily_breakout_rollback_lab() -> dict:
    start_utc = str(SWING_STALL_TUNING_START_UTC or "").strip()
    start_dt = _p175_parse_dt(start_utc) if start_utc else None
    pre_limit = max(
        5,
        int(SWING_ROLLBACK_LAB_PRE_WINDOW_TRADES or 30),
    )

    attributed = _p261_broker_preferred_attributed_rows()
    all_rows = [
        dict(row)
        for row in list(attributed.get("rows") or [])
        if isinstance(row, dict)
    ]
    breakout_rows = [
        row for row in all_rows
        if _p262_strategy(row) == "daily_breakout"
    ]

    if not start_dt:
        return {
            "ok": False,
            "patch_version": PATCH_VERSION,
            "mode": "daily_breakout_entry_cohort_rollback_lab",
            "error": "SWING_STALL_TUNING_START_UTC_not_configured",
            "recommended_action": "configure_post_change_start_utc",
        }

    pre_rows, post_entry_rows, carried_rows = (
        _p262_split_entry_cohorts(
            breakout_rows,
            start_dt,
            pre_limit,
        )
    )

    post_exit_rows = [
        row for row in breakout_rows
        if (
            _p212_closed_trade_ts(row)
            and _p212_closed_trade_ts(row) >= start_dt
        )
    ]

    coverage = _p262_attribute_coverage(breakout_rows)
    post_coverage = _p262_attribute_coverage(post_entry_rows)

    scenarios = [
        _p262_filter_scenario(
            name="exclude_defensive_entry_cohorts",
            rows=breakout_rows,
            start_dt=start_dt,
            pre_limit=pre_limit,
            keep_fn=lambda row: _p262_regime(row) != "defensive",
            rationale=(
                "Tests whether defensive-regime breakout entries damaged "
                "both historical and post-change performance."
            ),
            env_hint=(
                "SWING_REGIME_MODE_ALLOW_DEFENSIVE_ENTRIES=false"
            ),
            required_attribute="regime_mode",
        ),
        _p262_filter_scenario(
            name="exclude_recovered_entry_cohorts",
            rows=breakout_rows,
            start_dt=start_dt,
            pre_limit=pre_limit,
            keep_fn=lambda row: not bool(row.get("recovered")),
            rationale=(
                "Tests whether recovered-plan attribution or recovered "
                "entries are driving the drawdown."
            ),
            env_hint="diagnostic_only_no_direct_env_change",
            required_attribute="recovered",
        ),
        _p262_filter_scenario(
            name="known_rank_minimum_95",
            rows=breakout_rows,
            start_dt=start_dt,
            pre_limit=pre_limit,
            keep_fn=lambda row: (
                _p262_rank(row) is None
                or _p262_rank(row) >= 95.0
            ),
            rationale=(
                "Applies a 95 rank floor only where historical rank "
                "attribution is available. Unknown ranks remain included."
            ),
            env_hint=(
                "SWING_TREND_BREAKOUT_MIN_RANK_SCORE=95;"
                "SWING_NEUTRAL_BREAKOUT_MIN_RANK_SCORE=95;"
                "SWING_DEFENSIVE_BREAKOUT_MIN_RANK_SCORE=95"
            ),
            required_attribute="rank_score",
        ),
        _p262_filter_scenario(
            name="known_rank_minimum_100",
            rows=breakout_rows,
            start_dt=start_dt,
            pre_limit=pre_limit,
            keep_fn=lambda row: (
                _p262_rank(row) is None
                or _p262_rank(row) >= 100.0
            ),
            rationale=(
                "Applies a stricter 100 rank floor only to trades with "
                "known historical rank attribution."
            ),
            env_hint=(
                "SWING_TREND_BREAKOUT_MIN_RANK_SCORE=100;"
                "SWING_NEUTRAL_BREAKOUT_MIN_RANK_SCORE=100;"
                "SWING_DEFENSIVE_BREAKOUT_MIN_RANK_SCORE=100"
            ),
            required_attribute="rank_score",
        ),
        _p262_daily_cap_scenario(
            name="max_3_daily_breakout_entries",
            rows=breakout_rows,
            start_dt=start_dt,
            pre_limit=pre_limit,
            cap=3,
        ),
        _p262_daily_cap_scenario(
            name="max_4_daily_breakout_entries",
            rows=breakout_rows,
            start_dt=start_dt,
            pre_limit=pre_limit,
            cap=4,
        ),
    ]

    minimum_coverage = float(
        SWING_ROLLBACK_LAB_MIN_ATTRIBUTE_COVERAGE or 0.60
    )
    for scenario in scenarios:
        required = str(
            scenario.get("required_attribute") or ""
        ).strip()
        if required == "rank_score":
            attribute_coverage = float(
                coverage.get("rank_coverage") or 0.0
            )
        elif required == "regime_mode":
            attribute_coverage = float(
                coverage.get("regime_coverage") or 0.0
            )
        else:
            attribute_coverage = 1.0

        scenario["attribute_coverage"] = round(
            attribute_coverage,
            4,
        )
        scenario["coverage_sufficient"] = bool(
            attribute_coverage >= minimum_coverage
        )

    scenarios.sort(
        key=lambda row: (
            bool(row.get("coverage_sufficient")),
            _safe_float(row.get("post_gross_pnl_delta"), 0.0),
            _safe_float(row.get("pre_gross_pnl_delta"), 0.0),
        ),
        reverse=True,
    )

    supported = [
        row for row in scenarios
        if row.get("coverage_sufficient")
        and int(row.get("removed_post_count") or 0) > 0
    ]
    best_supported = supported[0] if supported else {}

    carried_gross = _safe_float(
        _p261_cohort_summary(carried_rows).get("gross_pnl"),
        0.0,
    )
    post_exit_gross = _safe_float(
        _p261_cohort_summary(post_exit_rows).get("gross_pnl"),
        0.0,
    )
    carried_share = (
        abs(carried_gross) / max(0.01, abs(post_exit_gross))
        if post_exit_gross < 0
        else 0.0
    )

    conclusions = []
    if carried_rows:
        conclusions.append(
            "post_change_exit_losses_include_pre_change_entries"
        )
    if carried_share >= 0.40:
        conclusions.append(
            "do_not_attribute_drawdown_to_entry_changes_alone"
        )
    if int(post_coverage.get("rank_count") or 0) == 0:
        conclusions.append(
            "post_change_rank_attribution_insufficient"
        )
    if not supported:
        conclusions.append(
            "no_rollback_scenario_has_sufficient_support"
        )

    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "daily_breakout_entry_cohort_rollback_lab",
        "read_only": True,
        "live_entry_rules_changed": False,
        "drawdown_circuit_remains_required": True,
        "post_change_start_utc": start_utc,
        "pre_window_trade_limit": pre_limit,
        "broker_preferred_source": {
            "raw_count": attributed.get("raw_count"),
            "kept_count": attributed.get("kept_count"),
            "shadowed_worker_count": (
                attributed.get("shadowed_worker_count")
            ),
            "attributed_exit_count": (
                attributed.get("attributed_exit_count")
            ),
        },
        "cohorts": {
            "all_daily_breakout": _p261_cohort_summary(
                breakout_rows
            ),
            "pre_change_entry_window": _p261_cohort_summary(
                pre_rows
            ),
            "post_change_entries": _p261_cohort_summary(
                post_entry_rows
            ),
            "post_change_exits": _p261_cohort_summary(
                post_exit_rows
            ),
            "carried_into_post_change_window": (
                _p261_cohort_summary(carried_rows)
            ),
        },
        "carried_position_analysis": {
            "count": len(carried_rows),
            "gross_pnl": round(carried_gross, 4),
            "share_of_post_exit_loss": round(
                carried_share,
                4,
            ),
            "symbols": sorted({
                str(row.get("symbol") or "").upper()
                for row in carried_rows
                if str(row.get("symbol") or "").strip()
            }),
        },
        "attribute_coverage": coverage,
        "post_change_attribute_coverage": post_coverage,
        "minimum_attribute_coverage": minimum_coverage,
        "scenarios": scenarios,
        "best_supported_scenario": best_supported,
        "conclusions": conclusions,
        "recent_post_change_entries": post_entry_rows[-25:],
        "carried_rows": carried_rows[-25:],
        "recommended_action": (
            "review_best_supported_rollback_before_env_change"
            if best_supported
            else "improve_entry_attribution_before_rollback"
        ),
        "operator_constraints": [
            "do_not_disable_drawdown_circuit_yet",
            "do_not_change_exit_execution_from_this_lab",
            "do_not_treat_removed_losers_as_proof_of_counterfactual_profit",
            "reset_post_change_start_only_after_rollback_selection",
        ],
    }

def _p263_missing_attribution_fields(row: dict | None) -> list[str]:
    row = dict(row or {})
    missing = []

    if _p262_rank(row) is None:
        missing.append("rank_score")
    if _p262_regime(row) == "unknown":
        missing.append("regime_mode")
    if _p262_entry_type(row) == "unknown":
        missing.append("entry_type")
    if row.get("selection_quality_score") in (None, "", [], {}):
        missing.append("selection_quality_score")
    if row.get("breakout_level") in (None, "", [], {}):
        missing.append("breakout_level")

    return missing


def _p263_parse_entry_caps() -> list[int]:
    caps = []
    for raw in str(SWING_ROLLBACK_LAB_ENTRY_CAPS or "").split(","):
        try:
            value = int(str(raw or "").strip())
        except Exception:
            continue
        if value > 0 and value not in caps:
            caps.append(value)

    return caps or [2, 3, 4, 5]


def _p263_candidate_match_for_trade(row: dict | None) -> dict:
    trade = dict(row or {})
    sym = str(trade.get("symbol") or "").strip().upper()
    entry_dt = _p262_entry_dt(trade)
    max_hours = max(1.0, float(SWING_ROLLBACK_LAB_ATTRIBUTION_MATCH_HOURS or 72.0))

    if not sym:
        return {}

    matches = []

    def add_candidate(candidate: dict | None, source: str, scan_ts: object = None, selected_symbols: set[str] | None = None, regime_mode: object = None):
        candidate = dict(candidate or {})
        if str(candidate.get("symbol") or "").strip().upper() != sym:
            return

        selected_symbols = selected_symbols or set()
        enriched_candidate = dict(candidate)
        if scan_ts not in (None, "", [], {}) and enriched_candidate.get("scan_ts_utc") in (None, "", [], {}):
            enriched_candidate["scan_ts_utc"] = scan_ts
        if regime_mode not in (None, "", [], {}) and enriched_candidate.get("regime_mode") in (None, "", [], {}):
            enriched_candidate["regime_mode"] = regime_mode

        candidate_dt = _p175_parse_dt(
            enriched_candidate.get("scan_ts_utc")
            or enriched_candidate.get("ts_utc")
            or enriched_candidate.get("candidate_ts")
        )

        distance_hours = None
        if entry_dt and candidate_dt:
            distance_hours = abs((entry_dt - candidate_dt).total_seconds()) / 3600.0
            if distance_hours > max_hours:
                return

        meta = _candidate_attribution_meta(enriched_candidate, source)
        if not meta:
            meta = {
                "strategy_name": BREAKOUT_STRATEGY_NAME,
                "signal": BREAKOUT_STRATEGY_NAME,
                "attribution_source": source,
            }

        selected = sym in selected_symbols or bool(enriched_candidate.get("selected"))
        score = 0.0
        if distance_hours is not None:
            score += max(0.0, 1000.0 - distance_hours)
        else:
            score += 25.0
        if selected:
            score += 100.0
        if bool(enriched_candidate.get("eligible")):
            score += 25.0
        if _safe_float(enriched_candidate.get("rank_score"), 0.0) > 0:
            score += 10.0

        matches.append({
            "score": round(score, 4),
            "distance_hours": round(distance_hours, 4) if distance_hours is not None else None,
            "source": source,
            "selected": bool(selected),
            "candidate": enriched_candidate,
            "meta": meta,
        })

    for hist in reversed(list(CANDIDATE_HISTORY or [])):
        if not isinstance(hist, dict):
            continue
        selected = {str(x or "").strip().upper() for x in list(hist.get("selected") or [])}
        rows = []
        rows.extend(list(hist.get("candidates") or []))
        rows.extend(list(hist.get("adaptive_capacity_candidates") or []))
        rows.extend(list(hist.get("shadow_candidates") or []))
        rows.extend(list((hist.get("summary") or {}).get("top_candidates") or []))
        for candidate in rows:
            if isinstance(candidate, dict):
                add_candidate(
                    candidate,
                    source="p263_candidate_history_selected" if sym in selected else "p263_candidate_history",
                    scan_ts=hist.get("ts_utc") or hist.get("scan_ts_utc"),
                    selected_symbols=selected,
                    regime_mode=hist.get("regime_mode"),
                )

    for candidate in reversed(list(LAST_SWING_CANDIDATES or [])):
        if isinstance(candidate, dict):
            add_candidate(candidate, source="p263_last_swing_candidates")

    for scan in reversed(list(SCAN_HISTORY or [])):
        if not isinstance(scan, dict):
            continue
        rows = []
        rows.extend(list(scan.get("would_submit") or []))
        rows.extend(list(scan.get("results") or []))
        rows.extend(list((scan.get("summary") or {}).get("top_candidates") or []))
        selected = {str(x or "").strip().upper() for x in list(scan.get("selected") or [])}
        for candidate in rows:
            if isinstance(candidate, dict):
                add_candidate(
                    candidate,
                    source="p263_scan_history_selected" if sym in selected else "p263_scan_history",
                    scan_ts=scan.get("ts_utc") or scan.get("scan_ts_utc"),
                    selected_symbols=selected,
                    regime_mode=scan.get("regime_mode"),
                )

    if not matches:
        return {}

    matches.sort(
        key=lambda item: (
            float(item.get("score") or 0.0),
            -float(item.get("distance_hours") if item.get("distance_hours") is not None else 999999.0),
        ),
        reverse=True,
    )
    return matches[0]


def _p263_enrich_trade_attribution(row: dict | None) -> dict:
    trade = dict(row or {})
    before_missing = _p263_missing_attribution_fields(trade)
    sources = []
    recovered_fields = []

    match = _p263_candidate_match_for_trade(trade)
    inferred = dict((match or {}).get("meta") or {})
    if inferred:
        sources.append(str(inferred.get("attribution_source") or "p263_candidate_match"))

    if not inferred:
        fallback = _infer_recovered_plan_attribution(
            str(trade.get("symbol") or ""),
            str(trade.get("entry_order_id") or trade.get("order_id") or ""),
        )
        if fallback:
            inferred = dict(fallback)
            sources.append(str(inferred.get("attribution_source") or "p263_existing_recovered_plan_inference"))

    for source_key, target_keys in {
        "strategy_name": ["strategy_name"],
        "signal": ["signal"],
        "rank_score": ["rank_score"],
        "selection_quality_score": ["selection_quality_score"],
        "entry_type": ["entry_type"],
        "regime_mode": ["entry_regime_mode", "regime_mode"],
        "breakout_level": ["breakout_level"],
        "stop_price": ["stop_price"],
        "take_price": ["take_price", "target_price"],
        "target_price": ["target_price"],
        "risk_per_share": ["risk_per_share"],
    }.items():
        value = inferred.get(source_key)
        if value in (None, "", [], {}):
            continue

        for target_key in target_keys:
            current = trade.get(target_key)
            if target_key in {"strategy_name", "signal"}:
                if _valid_strategy_identity(current):
                    continue
                value = _valid_strategy_identity(value)
                if not value:
                    continue
            elif current not in (None, "", [], {}):
                continue

            trade[target_key] = value
            recovered_fields.append(target_key)

    after_missing = _p263_missing_attribution_fields(trade)
    trade["p263_attribution_recovered"] = bool(len(after_missing) < len(before_missing))
    trade["p263_attribution_recovered_fields"] = sorted(set(recovered_fields))
    trade["p263_attribution_missing_before"] = before_missing
    trade["p263_attribution_missing_after"] = after_missing
    trade["p263_attribution_source"] = ",".join(sorted(set(sources))) if sources else "none"
    trade["p263_candidate_match"] = {
        "source": match.get("source") if match else None,
        "distance_hours": match.get("distance_hours") if match else None,
        "selected": bool(match.get("selected")) if match else False,
        "score": match.get("score") if match else None,
    }

    return trade


def _p263_attribution_recovery_summary(before_rows: list[dict], after_rows: list[dict]) -> dict:
    before = _p262_attribute_coverage(before_rows)
    after = _p262_attribute_coverage(after_rows)
    recovered_rows = [row for row in after_rows if bool(row.get("p263_attribution_recovered"))]

    source_counts: dict[str, int] = {}
    for row in after_rows:
        source = str(row.get("p263_attribution_source") or "none")
        source_counts[source] = source_counts.get(source, 0) + 1

    return {
        "before": before,
        "after": after,
        "recovered_row_count": len(recovered_rows),
        "recovered_symbols": sorted({
            str(row.get("symbol") or "").strip().upper()
            for row in recovered_rows
            if str(row.get("symbol") or "").strip()
        }),
        "source_counts": source_counts,
        "minimum_attribute_coverage": float(SWING_ROLLBACK_LAB_MIN_ATTRIBUTE_COVERAGE or 0.60),
    }


def _p263_entry_date_key(row: dict | None) -> str:
    dt = _p262_entry_dt(row)
    if not dt:
        return "unknown"
    return dt.astimezone(NY_TZ).date().isoformat()


def _p263_filter_entry_time_daily_cap(rows: list[dict], cap: int) -> tuple[list[dict], list[dict]]:
    grouped: dict[str, list[dict]] = {}
    for row in [dict(r) for r in list(rows or []) if isinstance(r, dict)]:
        grouped.setdefault(_p263_entry_date_key(row), []).append(row)

    kept = []
    removed = []
    for _, bucket in grouped.items():
        bucket.sort(
            key=lambda item: (
                _p262_entry_dt(item) or _p212_closed_trade_ts(item) or datetime.min.replace(tzinfo=timezone.utc),
                -_safe_float(item.get("rank_score"), 0.0),
            )
        )
        kept.extend(bucket[:max(0, int(cap))])
        removed.extend(bucket[max(0, int(cap)):])

    return kept, removed


def _p263_entry_time_cap_scenario(
    name: str,
    rows: list[dict],
    start_dt,
    pre_limit: int,
    cap: int,
) -> dict:
    kept_rows, removed_rows = _p263_filter_entry_time_daily_cap(rows, cap)
    removed_ids = {id(row) for row in removed_rows}
    removed_fingerprints = {
        (
            str(row.get("symbol") or "").upper(),
            str(row.get("entry_order_id") or row.get("entry_ts_utc") or row.get("ts_utc") or ""),
        )
        for row in removed_rows
    }

    scenario = _p262_filter_scenario(
        name=name,
        rows=rows,
        start_dt=start_dt,
        pre_limit=pre_limit,
        keep_fn=lambda row: (
            (
                str(row.get("symbol") or "").upper(),
                str(row.get("entry_order_id") or row.get("entry_ts_utc") or row.get("ts_utc") or ""),
            )
            not in removed_fingerprints
        ),
        rationale=f"Entry-time replay limiting daily breakout entries to {int(cap)} per NY trading day.",
        env_hint=f"SWING_MAX_NEW_ENTRIES_PER_DAY={int(cap)}",
    )
    scenario["replay_basis"] = "entry_time_ny_date"
    scenario["cap"] = int(cap)
    scenario["removed_entry_dates"] = sorted({
        _p263_entry_date_key(row)
        for row in removed_rows
    })
    scenario["removed_post_rows"] = [
        row for row in removed_rows
        if _p262_entry_dt(row) and _p262_entry_dt(row) >= start_dt
    ][-25:]
    return scenario


def _p263_rank_floor_scenario(
    name: str,
    rows: list[dict],
    start_dt,
    pre_limit: int,
    floor: float,
) -> dict:
    return _p262_filter_scenario(
        name=name,
        rows=rows,
        start_dt=start_dt,
        pre_limit=pre_limit,
        keep_fn=lambda row: (
            _p262_rank(row) is None
            or _p262_rank(row) >= float(floor)
        ),
        rationale=f"Recovered-attribution replay applying rank floor {float(floor):.1f}; unknown ranks remain included.",
        env_hint=(
            f"SWING_TREND_BREAKOUT_MIN_RANK_SCORE={float(floor):.0f};"
            f"SWING_NEUTRAL_BREAKOUT_MIN_RANK_SCORE={float(floor):.0f};"
            f"SWING_DEFENSIVE_BREAKOUT_MIN_RANK_SCORE={float(floor):.0f}"
        ),
        required_attribute="rank_score",
    )


def _p263_quality_filter_scenarios(rows: list[dict], start_dt, pre_limit: int) -> list[dict]:
    return [
        _p262_filter_scenario(
            name="exclude_defensive_after_recovery",
            rows=rows,
            start_dt=start_dt,
            pre_limit=pre_limit,
            keep_fn=lambda row: _p262_regime(row) != "defensive",
            rationale="Recovered-attribution replay excluding defensive-regime daily breakout entries.",
            env_hint="SWING_REGIME_MODE_ALLOW_DEFENSIVE_ENTRIES=false",
            required_attribute="regime_mode",
        ),
        _p262_filter_scenario(
            name="exclude_recovered_after_recovery",
            rows=rows,
            start_dt=start_dt,
            pre_limit=pre_limit,
            keep_fn=lambda row: not bool(row.get("recovered")),
            rationale="Replay excluding recovered broker/order attributed rows.",
            env_hint="diagnostic_only_no_direct_env_change",
            required_attribute="recovered",
        ),
        _p263_rank_floor_scenario(
            name="rank_floor_95_after_recovery",
            rows=rows,
            start_dt=start_dt,
            pre_limit=pre_limit,
            floor=95.0,
        ),
        _p263_rank_floor_scenario(
            name="rank_floor_100_after_recovery",
            rows=rows,
            start_dt=start_dt,
            pre_limit=pre_limit,
            floor=100.0,
        ),
        _p263_rank_floor_scenario(
            name="rank_floor_105_after_recovery",
            rows=rows,
            start_dt=start_dt,
            pre_limit=pre_limit,
            floor=105.0,
        ),
    ]


def _p263_mark_scenario_support(scenarios: list[dict], coverage: dict) -> list[dict]:
    minimum = float(SWING_ROLLBACK_LAB_MIN_ATTRIBUTE_COVERAGE or 0.60)

    for scenario in scenarios:
        required = str(scenario.get("required_attribute") or "").strip()
        if required == "rank_score":
            attribute_coverage = float(coverage.get("rank_coverage") or 0.0)
        elif required == "regime_mode":
            attribute_coverage = float(coverage.get("regime_coverage") or 0.0)
        else:
            attribute_coverage = 1.0

        scenario["attribute_coverage"] = round(attribute_coverage, 4)
        scenario["coverage_sufficient"] = bool(attribute_coverage >= minimum)
        scenario["post_helpful"] = bool(float(scenario.get("post_gross_pnl_delta") or 0.0) > 0.0)
        scenario["pre_helpful"] = bool(float(scenario.get("pre_gross_pnl_delta") or 0.0) > 0.0)

    scenarios.sort(
        key=lambda row: (
            bool(row.get("coverage_sufficient")),
            bool(row.get("post_helpful")),
            _safe_float(row.get("post_gross_pnl_delta"), 0.0),
            _safe_float(row.get("pre_gross_pnl_delta"), 0.0),
        ),
        reverse=True,
    )
    return scenarios


def _p263_daily_breakout_attribution_recovery_lab() -> dict:
    start_utc = str(SWING_STALL_TUNING_START_UTC or "").strip()
    start_dt = _p175_parse_dt(start_utc) if start_utc else None
    pre_limit = max(5, int(SWING_ROLLBACK_LAB_PRE_WINDOW_TRADES or 30))

    attributed = _p261_broker_preferred_attributed_rows()
    raw_rows = [
        dict(row)
        for row in list(attributed.get("rows") or [])
        if isinstance(row, dict) and _p262_strategy(row) == "daily_breakout"
    ]

    if not start_dt:
        return {
            "ok": False,
            "patch_version": PATCH_VERSION,
            "mode": "daily_breakout_attribution_recovery_entry_time_replay",
            "error": "SWING_STALL_TUNING_START_UTC_not_configured",
            "recommended_action": "configure_post_change_start_utc",
        }

    enriched_rows = [_p263_enrich_trade_attribution(row) for row in raw_rows]
    pre_rows, post_entry_rows, carried_rows = _p262_split_entry_cohorts(
        enriched_rows,
        start_dt,
        pre_limit,
    )
    post_exit_rows = [
        row for row in enriched_rows
        if _p212_closed_trade_ts(row) and _p212_closed_trade_ts(row) >= start_dt
    ]

    recovery = _p263_attribution_recovery_summary(raw_rows, enriched_rows)
    coverage_after = dict(recovery.get("after") or {})

    scenarios = []
    for cap in _p263_parse_entry_caps():
        scenarios.append(
            _p263_entry_time_cap_scenario(
                name=f"entry_time_max_{int(cap)}_daily_breakout_entries",
                rows=enriched_rows,
                start_dt=start_dt,
                pre_limit=pre_limit,
                cap=int(cap),
            )
        )
    scenarios.extend(_p263_quality_filter_scenarios(enriched_rows, start_dt, pre_limit))
    scenarios = _p263_mark_scenario_support(scenarios, coverage_after)

    supported = [
        row for row in scenarios
        if bool(row.get("coverage_sufficient"))
        and (
            float(row.get("post_gross_pnl_delta") or 0.0) > 0.0
            or int(row.get("removed_post_count") or 0) > 0
        )
    ]
    best_supported = supported[0] if supported else {}

    conclusions = []
    if float((recovery.get("after") or {}).get("rank_coverage") or 0.0) > float((recovery.get("before") or {}).get("rank_coverage") or 0.0):
        conclusions.append("rank_attribution_improved")
    if float((recovery.get("after") or {}).get("regime_coverage") or 0.0) > float((recovery.get("before") or {}).get("regime_coverage") or 0.0):
        conclusions.append("regime_attribution_improved")
    if carried_rows:
        conclusions.append("post_change_losses_include_carried_positions")
    if not best_supported:
        conclusions.append("no_supported_rollback_selected_yet")
    if best_supported:
        conclusions.append("supported_rollback_candidate_available")

    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "daily_breakout_attribution_recovery_entry_time_replay",
        "read_only": True,
        "live_entry_rules_changed": False,
        "drawdown_circuit_remains_required": True,
        "post_change_start_utc": start_utc,
        "pre_window_trade_limit": pre_limit,
        "attribution_match_hours": float(SWING_ROLLBACK_LAB_ATTRIBUTION_MATCH_HOURS or 72.0),
        "entry_caps_tested": _p263_parse_entry_caps(),
        "broker_preferred_source": {
            "raw_count": attributed.get("raw_count"),
            "kept_count": attributed.get("kept_count"),
            "shadowed_worker_count": attributed.get("shadowed_worker_count"),
            "attributed_exit_count": attributed.get("attributed_exit_count"),
        },
        "cohorts_after_recovery": {
            "all_daily_breakout": _p261_cohort_summary(enriched_rows),
            "pre_change_entry_window": _p261_cohort_summary(pre_rows),
            "post_change_entries": _p261_cohort_summary(post_entry_rows),
            "post_change_exits": _p261_cohort_summary(post_exit_rows),
            "carried_into_post_change_window": _p261_cohort_summary(carried_rows),
        },
        "attribution_recovery": recovery,
        "entry_time_cap_scenarios": [
            row for row in scenarios
            if str(row.get("scenario") or "").startswith("entry_time_max_")
        ],
        "quality_filter_scenarios": [
            row for row in scenarios
            if not str(row.get("scenario") or "").startswith("entry_time_max_")
        ],
        "all_scenarios_ranked": scenarios,
        "best_supported_scenario": best_supported,
        "recent_post_change_entries_after_recovery": post_entry_rows[-25:],
        "carried_rows_after_recovery": carried_rows[-25:],
        "conclusions": conclusions,
        "recommended_action": (
            "review_best_supported_rollback_before_env_change"
            if best_supported
            else "keep_drawdown_circuit_active_collect_more_or_improve_attribution"
        ),
        "operator_constraints": [
            "read_only_no_live_rule_change",
            "do_not_disable_drawdown_circuit_yet",
            "do_not_change_exit_execution_from_this_lab",
            "use_best_supported_scenario_only_after_review",
        ],
    }

def _p264_daily_breakout_circuit_release_criteria() -> dict:
    p263 = _p263_daily_breakout_attribution_recovery_lab()
    circuit = _p261_post_change_drawdown_snapshot()

    attribution = dict((p263.get("attribution_recovery") or {}).get("after") or {})
    best = dict(p263.get("best_supported_scenario") or {})
    best_name = str(best.get("scenario") or "").strip()
    best_supported = bool(best.get("coverage_sufficient")) and bool(best.get("post_helpful"))

    rank_coverage = float(attribution.get("rank_coverage") or 0.0)
    regime_coverage = float(attribution.get("regime_coverage") or 0.0)
    min_coverage = float(SWING_DAILY_BREAKOUT_RELEASE_MIN_ATTRIBUTION_COVERAGE or 0.80)
    defensive_rollback_active = bool(not SWING_REGIME_MODE_ALLOW_DEFENSIVE_ENTRIES)

    blockers = []
    if not p263.get("ok"):
        blockers.append("attribution_recovery_lab_not_ok")
    if rank_coverage < min_coverage:
        blockers.append("rank_attribution_coverage_below_release_min")
    if regime_coverage < min_coverage:
        blockers.append("regime_attribution_coverage_below_release_min")
    if best_name != "exclude_defensive_after_recovery":
        blockers.append("best_supported_scenario_not_defensive_rollback")
    if not best_supported:
        blockers.append("best_supported_scenario_not_post_helpful")
    if (
        SWING_DAILY_BREAKOUT_RELEASE_REQUIRE_DEFENSIVE_ROLLBACK
        and not defensive_rollback_active
    ):
        blockers.append("defensive_rollback_env_not_active")
    if not circuit.get("block_new_entries"):
        blockers.append("drawdown_circuit_not_currently_blocking")

    release_candidate = bool(
        p263.get("ok")
        and rank_coverage >= min_coverage
        and regime_coverage >= min_coverage
        and best_name == "exclude_defensive_after_recovery"
        and best_supported
        and (
            defensive_rollback_active
            or not SWING_DAILY_BREAKOUT_RELEASE_REQUIRE_DEFENSIVE_ROLLBACK
        )
        and circuit.get("block_new_entries")
    )

    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "daily_breakout_circuit_release_criteria",
        "read_only": True,
        "release_candidate": release_candidate,
        "blockers": blockers,
        "defensive_daily_breakout_rollback_active": defensive_rollback_active,
        "mean_reversion_preserved": True,
        "drawdown_circuit": {
            "triggered": bool(circuit.get("triggered")),
            "block_new_entries": bool(circuit.get("block_new_entries")),
            "guarded_strategies": list(circuit.get("guarded_strategies") or []),
            "totals": dict(circuit.get("totals") or {}),
        },
        "best_supported_scenario": best,
        "attribution_coverage_after_recovery": attribution,
        "release_min_attribution_coverage": min_coverage,
        "recommended_action": (
            "review_release_of_post_change_drawdown_circuit_for_non_defensive_breakout"
            if release_candidate
            else "keep_post_change_drawdown_circuit_active"
        ),
        "operator_note": (
            "This diagnostic does not change live rules. If release_candidate is true, "
            "the next step is an operator-reviewed env release of the broad drawdown circuit "
            "while keeping defensive daily breakout disabled."
        ),
        "env_for_targeted_rollback": {
            "SWING_REGIME_MODE_ALLOW_DEFENSIVE_ENTRIES": False,
        },
        "possible_future_release_env_after_review": {
            "SWING_POST_CHANGE_DRAWDOWN_ADVISORY_ONLY": True,
        },
    }

def _stall_exit_tuning_monitor(perf_state: dict | None = None) -> dict:
    state = perf_state if isinstance(perf_state, dict) else _recompute_strategy_performance_state()
    state, _ = _patch175_enrich_state_if_needed(state)
    attributed = _p261_broker_preferred_attributed_rows(perf_state=state)
    rows = [
        dict(row)
        for row in list(attributed.get("rows") or [])
        if isinstance(row, dict)
    ]
    start_utc = str(SWING_STALL_TUNING_START_UTC or "").strip()
    rows_since = _p212_rows_since(rows, start_utc)
    stall_since = [r for r in rows_since if _p261_is_stall_family_exit(r)]
    negative_stall_since = [r for r in stall_since if (_p175_closed_trade_r(r) is not None and float(_p175_closed_trade_r(r) or 0.0) < 0)]
    deep_stall_since = [r for r in stall_since if (_p175_closed_trade_r(r) is not None and float(_p175_closed_trade_r(r) or 0.0) <= float(SWING_PERFORMANCE_RISK_SCALE_MAX_WORST_R))]
    stall_summary = _p210_rows_summary(stall_since).get("totals")
    since_summary = _p210_rows_summary(rows_since).get("totals")
    changed = abs(float(SWING_STALL_MIN_R or 0.0) - float(SWING_STALL_TUNING_BASELINE_MIN_R or 0.0)) > 1e-9
    active = bool(changed or start_utc)
    assessment = "monitoring_post_change" if active else "baseline_not_changed"
    if active and int(stall_summary.get("closed_trades") or 0) == 0:
        assessment = "active_no_stall_exits_since_start"
    elif active and int(deep_stall_since and len(deep_stall_since) or 0) > 0:
        assessment = "active_but_deep_stall_exits_remain"
    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "read_only_monitor",
        "active_SWING_STALL_MIN_R": float(SWING_STALL_MIN_R or 0.0),
        "baseline_SWING_STALL_MIN_R": float(SWING_STALL_TUNING_BASELINE_MIN_R or 0.0),
        "active_SWING_STALL_EXIT_DAYS": int(SWING_STALL_EXIT_DAYS or 0),
        "active_SWING_STALL_LOSS_GUARD_ENABLED": bool(SWING_STALL_LOSS_GUARD_ENABLED),
        "active_SWING_STALL_LOSS_GUARD_DAYS": int(SWING_STALL_LOSS_GUARD_DAYS or 0),
        "active_SWING_STALL_MAX_LOSS_R": float(SWING_STALL_MAX_LOSS_R or 0.0),
        "stall_tuning_active": bool(active),
        "stall_tuning_changed_from_default": bool(changed),
        "stall_tuning_start_utc": start_utc,
        "post_tuning_window_configured": bool(start_utc),
        "closed_trades_since_tuning": int(since_summary.get("closed_trades") or 0),
        "stall_exits_since_tuning": int(stall_summary.get("closed_trades") or 0),
                "classic_stall_exits_since_tuning": sum(
            1 for row in stall_since
            if _p261_exit_reason(row) == "stall_exit"
        ),
        "stall_loss_guard_exits_since_tuning": sum(
            1 for row in stall_since
            if _p261_exit_reason(row) == "stall_loss_guard"
        ),
        "stall_exit_gross_pnl_since_tuning": stall_summary.get("gross_pnl"),
        "stall_exit_avg_r_since_tuning": stall_summary.get("avg_r"),
        "stall_exit_worst_r_since_tuning": stall_summary.get("worst_r"),
        "negative_stall_exit_count_since_tuning": len(negative_stall_since),
        "deep_stall_exit_count_since_tuning": len(deep_stall_since),
        "assessment": assessment,
        "recommended_next_step": "collect_more_post_change_stall_exits" if active else "set_SWING_STALL_MIN_R_or_start_utc_when_tuning",
        "recent_stall_exits": [_p208_trade_drilldown_row(r) for r in stall_since[-10:]],
        "config": {
            "set_SWING_STALL_TUNING_START_UTC_for_true_post_change_window": not bool(start_utc),
            "read_only": True,
        },
    }


def _post_tuning_exit_validation(perf_state: dict | None = None) -> dict:
    state = perf_state if isinstance(perf_state, dict) else _recompute_strategy_performance_state()
    state, _ = _patch175_enrich_state_if_needed(state)
    rows = [dict(r) for r in list((state or {}).get("closed_trades") or []) if isinstance(r, dict)]
    start_utc = str(SWING_STALL_TUNING_START_UTC or "").strip()
    pre_rows = []
    post_rows = _p212_rows_since(rows, start_utc)
    start_dt = _p175_parse_dt(start_utc) if start_utc else None
    if start_dt:
        for row in rows:
            ts = _p212_closed_trade_ts(row)
            if ts and ts < start_dt:
                pre_rows.append(row)
    post_stalls = [r for r in post_rows if _p211_is_stall_exit(r)]
    pre_stalls = [r for r in pre_rows if _p211_is_stall_exit(r)]
    post_summary = _p210_rows_summary(post_rows)
    pre_summary = _p210_rows_summary(pre_rows)
    post_stall_summary = _p210_rows_summary(post_stalls)
    pre_stall_summary = _p210_rows_summary(pre_stalls)
    post_totals = _p210_safe_dict(post_summary.get("totals"))
    post_stall_totals = _p210_safe_dict(post_stall_summary.get("totals"))
    post_risk = _p210_safe_dict(post_summary.get("risk_scaling"))
    post_stall_avg_r = _p175_float(post_stall_totals.get("avg_r"), None)
    post_stall_worst_r = _p175_float(post_stall_totals.get("worst_r"), None)
    post_trades = int(post_totals.get("closed_trades") or 0)
    post_stall_count = int(post_stall_totals.get("closed_trades") or 0)
    negative_post_stalls = [r for r in post_stalls if (_p175_closed_trade_r(r) is not None and float(_p175_closed_trade_r(r) or 0.0) < 0)]
    deep_post_stalls = [r for r in post_stalls if (_p175_closed_trade_r(r) is not None and float(_p175_closed_trade_r(r) or 0.0) <= float(SWING_PERFORMANCE_RISK_SCALE_MAX_WORST_R))]
    blockers = []
    if not start_dt:
        blockers.append("post_tuning_start_not_configured")
    if post_trades < 10:
        blockers.append("post_tuning_sample_below_10_closed_trades")
    if post_stall_count < 1:
        blockers.append("no_post_tuning_stall_exit_sample_yet")
    if deep_post_stalls:
        blockers.append("deep_post_tuning_stall_exit_remains")
    if post_stall_avg_r is not None and post_stall_avg_r < 0.0:
        blockers.append("post_tuning_stall_avg_r_still_negative")
    if post_stall_worst_r is not None and post_stall_worst_r < -1.0:
        blockers.append("post_tuning_stall_worst_r_below_minus_1")
    risk_unlock_blockers = list(blockers)
    if float(post_totals.get("avg_r") or 0.0) < float(SWING_PERFORMANCE_RISK_40_MIN_AVG_R):
        risk_unlock_blockers.append("post_tuning_avg_r_below_40_risk_min")
    if float(post_totals.get("win_rate") or 0.0) < float(SWING_PERFORMANCE_RISK_MIN_WIN_RATE):
        risk_unlock_blockers.append("post_tuning_win_rate_below_risk_min")
    validation_ready = not blockers
    risk_unlock_candidate = bool(validation_ready and not risk_unlock_blockers)
    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "read_only_validation",
        "post_tuning_start_utc": start_utc,
        "post_tuning_window_configured": bool(start_dt),
        "pre_tuning_totals": pre_summary.get("totals"),
        "post_tuning_totals": post_totals,
        "pre_tuning_stall_exit_summary": pre_stall_summary.get("totals"),
        "post_tuning_stall_exit_summary": post_stall_totals,
        "post_tuning_risk_scaling": post_risk,
        "post_tuning_closed_trades": post_trades,
        "post_tuning_stall_exits": post_stall_count,
        "post_tuning_negative_stall_exits": len(negative_post_stalls),
        "post_tuning_deep_stall_exits": len(deep_post_stalls),
        "post_tuning_validation_ready": bool(validation_ready),
        "ready_for_40_after_post_tuning": bool(risk_unlock_candidate),
        "risk_scale_unlock_candidate": bool(risk_unlock_candidate),
        "risk_scale_unlock_blockers": risk_unlock_blockers,
        "recommended_action": "consider_unlocking_40_risk_after_operator_review" if risk_unlock_candidate else "continue_collecting_post_tuning_exit_sample",
        "criteria": {
            "min_post_tuning_closed_trades": 10,
            "requires_post_tuning_stall_exit_sample": True,
            "max_post_tuning_stall_worst_r": -1.0,
            "min_post_tuning_stall_avg_r": 0.0,
            "risk_40_min_avg_r": float(SWING_PERFORMANCE_RISK_40_MIN_AVG_R),
            "risk_min_win_rate": float(SWING_PERFORMANCE_RISK_MIN_WIN_RATE),
            "read_only": True,
        },
    }

def _p257_current_open_stall_risk_preview() -> dict:
    advisory = _p250_entry_quality_exit_advisory_snapshot()
    rows = []
    guard_r = float(SWING_STALL_MAX_LOSS_R or -0.60)
    guard_days = int(SWING_STALL_LOSS_GUARD_DAYS or 0)
    warning_band_r = 0.25

    for raw in list(advisory.get("rows") or []):
        row = dict(raw or {})
        current_r = row.get("current_r")
        try:
            current_r_float = float(current_r)
        except Exception:
            current_r_float = None

        days_held = int(row.get("days_held") or 0)
        guard_armed = bool(SWING_STALL_LOSS_GUARD_ENABLED and days_held >= guard_days)
        guard_due = bool((row.get("stall_projection") or {}).get("stall_loss_guard_due"))

        r_to_guard = None
        near_guard = False
        if current_r_float is not None:
            r_to_guard = round(current_r_float - guard_r, 4)
            near_guard = bool(guard_armed and current_r_float <= (guard_r + warning_band_r))

        if guard_due:
            recommended_action = "stall_loss_guard_due_or_imminent"
        elif near_guard:
            recommended_action = "watch_near_stall_loss_guard"
        elif current_r_float is not None and current_r_float < 0:
            recommended_action = "monitor_negative_r"
        else:
            recommended_action = "normal_hold"

        rows.append({
            "symbol": row.get("symbol"),
            "current_r": current_r_float,
            "days_held": days_held,
            "guard_enabled": bool(SWING_STALL_LOSS_GUARD_ENABLED),
            "guard_armed": guard_armed,
            "guard_days": guard_days,
            "guard_threshold_r": guard_r,
            "r_to_guard": r_to_guard,
            "near_guard": near_guard,
            "guard_due": guard_due,
            "entry_price": row.get("entry_price"),
            "last_price": row.get("last_price"),
            "stop_price": row.get("stop_price"),
            "target_price": row.get("target_price"),
            "risk_per_share": row.get("risk_per_share"),
            "distance_to_stop_pct": row.get("distance_to_stop_pct"),
            "reasons": list(row.get("reasons") or []),
            "recommended_action": recommended_action,
        })

    rows.sort(key=lambda r: (
        0 if r.get("guard_due") else 1,
        0 if r.get("near_guard") else 1,
        _safe_float(r.get("r_to_guard"), 999.0),
    ))

    guard_due_rows = [r for r in rows if r.get("guard_due")]
    near_guard_rows = [r for r in rows if r.get("near_guard") and not r.get("guard_due")]
    negative_rows = [r for r in rows if r.get("current_r") is not None and float(r.get("current_r") or 0.0) < 0]

    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "current_open_stall_risk_preview",
        "read_only": True,
        "guard_enabled": bool(SWING_STALL_LOSS_GUARD_ENABLED),
        "guard_threshold_r": guard_r,
        "guard_days": guard_days,
        "active_position_count": len(rows),
        "guard_due_count": len(guard_due_rows),
        "near_guard_count": len(near_guard_rows),
        "negative_r_count": len(negative_rows),
        "guard_due_symbols": [r.get("symbol") for r in guard_due_rows],
        "near_guard_symbols": [r.get("symbol") for r in near_guard_rows],
        "rows": rows,
        "recommended_action": (
            "expect_worker_exit_to_process_guard_due_positions"
            if guard_due_rows
            else "watch_near_guard_positions"
            if near_guard_rows
            else "monitor_open_positions"
        ),
    }


def _p257_stall_loss_guard_live_validation() -> dict:
    monitor = _stall_exit_tuning_monitor()
    validation = _post_tuning_exit_validation()
    open_risk = _p257_current_open_stall_risk_preview()
    leak = _p256_stall_exit_profit_leak_drilldown()

    guard_r = float(SWING_STALL_MAX_LOSS_R or -0.60)
    expected_guard_r = -0.40
    guard_env_ready = bool(
        SWING_STALL_LOSS_GUARD_ENABLED
        and int(SWING_STALL_LOSS_GUARD_DAYS or 0) == 1
        and abs(guard_r - expected_guard_r) <= 1e-9
    )

    blockers = []
    if not SWING_STALL_LOSS_GUARD_ENABLED:
        blockers.append("stall_loss_guard_disabled")
    if abs(guard_r - expected_guard_r) > 1e-9:
        blockers.append("stall_loss_guard_not_set_to_minus_0_40r")
    if not str(SWING_STALL_TUNING_START_UTC or "").strip():
        blockers.append("stall_tuning_start_utc_missing")
    if int(monitor.get("closed_trades_since_tuning") or 0) < 10:
        blockers.append("post_change_closed_trade_sample_below_10")
    if int(monitor.get("stall_exits_since_tuning") or 0) < 1:
        blockers.append("no_post_change_stall_exit_sample_yet")
    if int(open_risk.get("guard_due_count") or 0) > 0:
        blockers.append("open_position_stall_guard_due")

    status = "ready_to_observe"
    if blockers:
        status = "collect_more_post_change_evidence"
    if "stall_loss_guard_disabled" in blockers or "stall_loss_guard_not_set_to_minus_0_40r" in blockers:
        status = "env_not_confirmed"
    if "open_position_stall_guard_due" in blockers:
        status = "guard_due_live_position_present"

    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "mode": "stall_loss_guard_live_validation",
        "read_only": True,
        "status": status,
        "blockers": blockers,
        "guard_env_ready": guard_env_ready,
        "configured": {
            "SWING_STALL_MAX_LOSS_R": guard_r,
            "expected_SWING_STALL_MAX_LOSS_R": expected_guard_r,
            "SWING_STALL_LOSS_GUARD_ENABLED": bool(SWING_STALL_LOSS_GUARD_ENABLED),
            "SWING_STALL_LOSS_GUARD_DAYS": int(SWING_STALL_LOSS_GUARD_DAYS or 0),
            "SWING_STALL_EXIT_DAYS": int(SWING_STALL_EXIT_DAYS or 0),
            "SWING_STALL_MIN_R": float(SWING_STALL_MIN_R or 0.0),
            "SWING_STALL_TUNING_START_UTC": str(SWING_STALL_TUNING_START_UTC or ""),
            "SWING_STALL_TUNING_BASELINE_MIN_R": float(SWING_STALL_TUNING_BASELINE_MIN_R or 0.0),
        },
        "post_change_monitor": monitor,
        "post_tuning_validation": validation,
        "current_open_stall_risk_preview": open_risk,
        "historical_loss_cap_best": leak.get("best_conservative_retune"),
        "historical_profit_leak": leak.get("profit_leak"),
        "recommended_action": (
            "verify_envs_then_redeploy"
            if status == "env_not_confirmed"
            else "watch_worker_exit_for_guard_due_positions"
            if status == "guard_due_live_position_present"
            else "collect_more_post_change_stall_exit_sample"
            if blockers
            else "continue_observing_minus_0_40r_guard"
        ),
    }

def _p207_bucket_summary(rows: list[dict], key_fn) -> list[dict]:
    buckets: dict[str, dict] = {}
    for raw in rows or []:
        row = raw if isinstance(raw, dict) else {}
        name = str(key_fn(row) or "unknown") or "unknown"
        bucket = buckets.setdefault(name, {"name": name, "closed_trades": 0, "wins": 0, "losses": 0, "flat": 0, "gross_pnl": 0.0, "best_r": None, "worst_r": None, "_r_sum": 0.0, "_r_count": 0})
        pnl = _p175_closed_trade_pnl(row)
        r_value = _p175_closed_trade_r(row)
        bucket["closed_trades"] += 1
        bucket["gross_pnl"] += pnl
        if pnl > 0:
            bucket["wins"] += 1
        elif pnl < 0:
            bucket["losses"] += 1
        else:
            bucket["flat"] += 1
        if r_value is not None:
            rv = float(r_value)
            bucket["_r_sum"] += rv
            bucket["_r_count"] += 1
            bucket["best_r"] = rv if bucket.get("best_r") is None else max(float(bucket["best_r"]), rv)
            bucket["worst_r"] = rv if bucket.get("worst_r") is None else min(float(bucket["worst_r"]), rv)
    out = []
    for bucket in buckets.values():
        count = max(1, int(bucket.get("closed_trades") or 0))
        r_count = int(bucket.pop("_r_count") or 0)
        r_sum = float(bucket.pop("_r_sum") or 0.0)
        bucket["gross_pnl"] = round(float(bucket.get("gross_pnl") or 0.0), 4)
        bucket["win_rate"] = round(float(bucket.get("wins") or 0) / count, 4)
        bucket["avg_r"] = round(r_sum / r_count, 4) if r_count else None
        if bucket.get("best_r") is not None:
            bucket["best_r"] = round(float(bucket["best_r"]), 4)
        if bucket.get("worst_r") is not None:
            bucket["worst_r"] = round(float(bucket["worst_r"]), 4)
        out.append(bucket)
    return sorted(out, key=lambda b: (float(b.get("gross_pnl") or 0.0), float(b.get("avg_r") or -999.0), int(b.get("closed_trades") or 0)), reverse=True)


def _p207_bucket_action(bucket: dict) -> dict:
    trades = int((bucket or {}).get("closed_trades") or 0)
    avg_r = _p175_float((bucket or {}).get("avg_r"), None)
    win_rate = _p175_float((bucket or {}).get("win_rate"), 0.0) or 0.0
    gross = float((bucket or {}).get("gross_pnl") or 0.0)
    if trades < max(1, int(SWING_PERFORMANCE_MIN_TRADES_PER_BUCKET or 1)):
        return {"action": "monitor", "reason": "sample_below_min", "min_trades": int(SWING_PERFORMANCE_MIN_TRADES_PER_BUCKET or 0)}
    if avg_r is not None and avg_r <= float(SWING_PERFORMANCE_QUARANTINE_MAX_AVG_R):
        return {"action": "quarantine", "reason": "avg_r_below_quarantine_threshold"}
    if gross < 0 or (avg_r is not None and avg_r <= float(SWING_PERFORMANCE_REDUCE_MAX_AVG_R)):
        return {"action": "reduce", "reason": "negative_or_weak_edge"}
    if trades >= max(1, int(SWING_PERFORMANCE_PROMOTE_MIN_TRADES or 1)) and avg_r is not None and avg_r >= float(SWING_PERFORMANCE_PROMOTE_MIN_AVG_R) and win_rate >= 0.50:
        return {"action": "promote", "reason": "positive_edge_established"}
    return {"action": "monitor", "reason": "edge_not_decisive"}


def _p207_risk_scaling_readiness(rows: list[dict], totals: dict | None = None) -> dict:
    totals = totals if isinstance(totals, dict) else {}
    trades = int(totals.get("closed_trades") or len(rows or []))
    wins = int(totals.get("wins") or sum(1 for r in rows or [] if _p175_closed_trade_pnl(r) > 0))
    win_rate = float(totals.get("win_rate") if totals.get("win_rate") is not None else (wins / max(1, trades)))
    r_values = [float(v) for v in (_p175_closed_trade_r(r) for r in rows or []) if v is not None]
    avg_r = float(totals.get("avg_r") if totals.get("avg_r") is not None else (sum(r_values) / max(1, len(r_values))))
    worst_r = min(r_values) if r_values else None
    blockers = []
    if trades < int(SWING_PERFORMANCE_RISK_SCALE_MIN_TRADES):
        blockers.append("sample_below_risk_scale_min")
    if win_rate < float(SWING_PERFORMANCE_RISK_MIN_WIN_RATE):
        blockers.append("win_rate_below_risk_scale_min")
    if avg_r < float(SWING_PERFORMANCE_RISK_40_MIN_AVG_R):
        blockers.append("avg_r_below_40_risk_min")
    if worst_r is not None and worst_r < float(SWING_PERFORMANCE_RISK_SCALE_MAX_WORST_R):
        blockers.append("worst_r_too_deep")
    ready_40 = not blockers
    ready_50 = bool(ready_40 and avg_r >= float(SWING_PERFORMANCE_RISK_50_MIN_AVG_R) and win_rate >= 0.58)
    return {
        "current_risk_dollars": round(float(RISK_DOLLARS or 0.0), 2),
        "ready_for_40_risk": bool(ready_40),
        "ready_for_50_risk": bool(ready_50),
        "recommended_risk_dollars": 50 if ready_50 else (40 if ready_40 else round(float(RISK_DOLLARS or 0.0), 2)),
        "closed_trades": trades,
        "win_rate": round(win_rate, 4),
        "avg_r": round(avg_r, 4),
        "worst_r": round(worst_r, 4) if worst_r is not None else None,
        "blockers": blockers,
        "assessment": "ready_for_50" if ready_50 else ("ready_for_40" if ready_40 else "not_ready"),
    }


def _swing_performance_attribution(perf_state: dict | None = None) -> dict:
    state = perf_state if isinstance(perf_state, dict) else _recompute_strategy_performance_state()
    state, _ = _patch175_enrich_state_if_needed(state)
    rows = [dict(r) for r in list((state or {}).get("closed_trades") or []) if isinstance(r, dict)]
    totals_list = _p207_bucket_summary(rows, lambda _r: "all")
    totals = totals_list[0] if totals_list else {"name": "all", "closed_trades": 0, "wins": 0, "losses": 0, "flat": 0, "gross_pnl": 0.0, "win_rate": 0.0, "avg_r": 0.0}
    by_symbol = _p207_bucket_summary(rows, lambda r: str(r.get("symbol") or "unknown").upper() or "unknown")
    by_strategy = _p207_bucket_summary(rows, _p207_closed_trade_strategy)
    by_entry_type = _p207_bucket_summary(rows, _p207_closed_trade_entry_type)
    by_exit_reason = _p207_bucket_summary(rows, _p207_closed_trade_exit_reason)
    by_holding_period = _p207_bucket_summary(rows, _p175_holding_bucket)
    recommendation_sources = {
        "symbols": by_symbol,
        "strategies": by_strategy,
        "entry_types": by_entry_type,
        "exit_reasons": by_exit_reason,
        "holding_periods": by_holding_period,
    }
    recommendations = {"promote": [], "reduce": [], "quarantine": [], "monitor": []}
    for category, buckets in recommendation_sources.items():
        for bucket in buckets:
            action = _p207_bucket_action(bucket)
            row = {"category": category, "name": bucket.get("name"), "closed_trades": bucket.get("closed_trades"), "gross_pnl": bucket.get("gross_pnl"), "avg_r": bucket.get("avg_r"), "win_rate": bucket.get("win_rate"), "reason": action.get("reason")}
            recommendations.setdefault(str(action.get("action") or "monitor"), []).append(row)
    for key in recommendations:
        recommendations[key] = sorted(recommendations[key], key=lambda r: (float(r.get("avg_r") or -999), float(r.get("gross_pnl") or 0)), reverse=(key == "promote"))[:12]
    risk_scaling = _p207_risk_scaling_readiness(rows, totals)
    risk_blocker_explanation = _p208_risk_blocker_explanation(rows, risk_scaling)
    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "totals": totals,
        "by_symbol": by_symbol,
        "by_strategy": by_strategy,
        "by_entry_type": by_entry_type,
        "by_exit_reason": by_exit_reason,
        "by_holding_period": by_holding_period,
        "recommendations": recommendations,
        "worst_trade_contributors": _p208_worst_trade_contributors(rows, limit=10),
        "risk_blocker_explanation": risk_blocker_explanation,
        "risk_scaling": risk_scaling,
        "quarantine_controls": {
            "symbols": sorted(SWING_QUARANTINE_SYMBOLS),
            "strategies": sorted(SWING_QUARANTINE_STRATEGIES),
            "entry_types": sorted(SWING_QUARANTINE_ENTRY_TYPES),
            "enforced": bool(SWING_QUARANTINE_ENFORCE),
            "read_only_until_enforced": not bool(SWING_QUARANTINE_ENFORCE),
        },
        "config": {
            "min_trades_per_bucket": int(SWING_PERFORMANCE_MIN_TRADES_PER_BUCKET or 0),
            "promote_min_trades": int(SWING_PERFORMANCE_PROMOTE_MIN_TRADES or 0),
            "promote_min_avg_r": float(SWING_PERFORMANCE_PROMOTE_MIN_AVG_R),
            "risk_scale_min_trades": int(SWING_PERFORMANCE_RISK_SCALE_MIN_TRADES or 0),
            "risk_40_min_avg_r": float(SWING_PERFORMANCE_RISK_40_MIN_AVG_R),
            "risk_50_min_avg_r": float(SWING_PERFORMANCE_RISK_50_MIN_AVG_R),
        },
    }


