@app.get("/dashboard/live", response_class=HTMLResponse)
def dashboard_live(request: Request):
    require_admin_if_configured(request)
    force = str(request.query_params.get("refresh") or request.query_params.get("force") or "").strip().lower() in {"1", "true", "yes", "y"}
    auto_refresh = str(request.query_params.get("auto") or "1").strip().lower() not in {"0", "false", "off", "no"}
    data = _live_operator_snapshot(force=force)
    summary = dict(data.get("summary") or {})
    pnl = dict(data.get("today_pnl") or {})
    perf = dict(data.get("performance") or {})
    halt = dict(data.get("loss_halt") or {})
    positions = list(data.get("positions") or [])
    orders = list(data.get("open_orders") or [])

    def _badge(value: str) -> str:
        text = html.escape(str(value or ""))
        cls = "good" if str(value).lower() in {"ok", "healthy", "true"} else ("bad" if str(value).lower() in {"bad", "false", "mismatch"} else "neutral")
        return f'<span class="badge {cls}">{text}</span>'

    def _signed_value_class(value: object) -> str:
        val = _safe_float(value, 0.0)
        if val > 0:
            return "good signed-value"
        if val < 0:
            return "bad signed-value"
        return "neutral signed-value"

    pos_rows = "".join(
        "<tr>"
        f"<td>{html.escape(str(row.get('symbol') or ''))}</td>"
        f"<td>{_badge(row.get('trust'))}</td>"
        f"<td>{html.escape(str((row.get('broker') or {}).get('side') or ''))}</td>"
        f"<td>{_dashboard_fmt((row.get('broker') or {}).get('qty'))}</td>"
        f"<td>{_dashboard_money((row.get('broker') or {}).get('avg_entry_price'))}</td>"
        f"<td>{_dashboard_money((row.get('broker') or {}).get('last_price'))}</td>"
        f"<td class='{_signed_value_class((row.get('broker') or {}).get('unrealized_pl'))}'>{_dashboard_money((row.get('broker') or {}).get('unrealized_pl'))}</td>"
        f"<td class='{_signed_value_class((row.get('broker') or {}).get('unrealized_plpc'))}'>{_dashboard_pct(_safe_float((row.get('broker') or {}).get('unrealized_plpc'), 0.0) * 100.0)}</td>"
        f"<td>{_dashboard_money((row.get('plan') or {}).get('stop_price'))}</td>"
        f"<td>{_dashboard_money((row.get('plan') or {}).get('take_price'))}</td>"
        f"<td>{html.escape(str((row.get('plan') or {}).get('signal') or ''))}</td>"
        f"<td>{html.escape(', '.join(row.get('warnings') or []) or 'none')}</td>"
        "</tr>"
        for row in positions
    ) or '<tr><td colspan="12" class="muted">No live broker positions, plans, or open orders.</td></tr>'
    halt_class = "bad" if halt.get("daily_halt_active") else "good"
    halt_actions = ", ".join(str(x) for x in (halt.get("recommended_actions") or [])) or "monitor"
    halt_rows = _dashboard_rows([
        ("daily_halt_active", halt.get("daily_halt_active")),
        ("daily_halt_reason", halt.get("daily_halt_reason")),
        ("account_daily_pnl", halt.get("account_daily_pnl")),
        ("today_realized_pnl", halt.get("today_realized_pnl")),
        ("today_unrealized_pnl", halt.get("today_unrealized_pnl")),
        ("configured_daily_stop_dollars", halt.get("configured_daily_stop_dollars")),
        ("new_entries_blocked", halt.get("new_entries_blocked")),
        ("exits_still_permitted", halt.get("exits_still_permitted")),
        ("bulk_flatten_allowed", halt.get("bulk_flatten_allowed")),
        ("recommended_action", halt.get("recommended_action")),
        ("recommended_actions", halt_actions),
    ])
    order_rows = "".join(
        f"<tr><td>{html.escape(str((o or {}).get('symbol') or ''))}</td><td>{html.escape(str((o or {}).get('side') or ''))}</td><td>{html.escape(str((o or {}).get('type') or ''))}</td><td>{_dashboard_fmt((o or {}).get('qty'))}</td><td>{_dashboard_fmt((o or {}).get('filled_qty'))}</td><td>{html.escape(str((o or {}).get('status') or ''))}</td><td>{html.escape(str((o or {}).get('submitted_at') or ''))}</td></tr>"
        for o in orders
    ) or '<tr><td colspan="7" class="muted">No open orders.</td></tr>'
    refresh_meta = '<meta http-equiv="refresh" content="15">' if auto_refresh else ''
    html_doc = f'''<!doctype html><html><head><meta charset="utf-8"><title>Live Operator Dashboard</title>{refresh_meta}<style>
    body{{font-family:Inter,system-ui,Arial,sans-serif;background:#0b0b16;color:#f6f4ff;margin:18px}} a{{color:#b9a7ff}} .muted{{color:#a9a1c4;font-size:12px}} .top{{display:flex;justify-content:space-between;gap:16px;align-items:flex-start}} .grid{{display:grid;grid-template-columns:repeat(4,minmax(180px,1fr));gap:12px;margin:14px 0}} .card{{background:#151522;border:1px solid #30245a;border-radius:10px;padding:14px}} .metric{{font-size:28px;font-weight:800}} .good{{color:#61f2a9}} .bad{{color:#ff5c8a}} .neutral{{color:#ffd36a}} .signed-value{{font-weight:800}} table{{width:100%;border-collapse:collapse;font-size:12px}} th,td{{border-bottom:1px solid #2a2540;padding:7px;text-align:left;vertical-align:top}} th{{color:#d7cbff}} .badge{{border:1px solid #49368a;border-radius:999px;padding:3px 7px;background:#24164c;font-size:11px}} .actions a{{display:inline-block;margin-left:8px;padding:7px 10px;border:1px solid #4c3d89;border-radius:8px;text-decoration:none}}</style></head><body>
    <div class="top"><div><div class="muted">OPERATOR CONSOLE</div><h1>Live Operator Dashboard</h1><p class="muted">Broker-backed live view. This page intentionally makes live broker/account calls and caches for {int(data.get('cache_ttl_sec') or 0)}s. Generated {html.escape(str(data.get('generated_utc')))}. Cached: {html.escape(str(data.get('cached')))}.</p></div><div class="actions"><a href="/dashboard/live?refresh=1">Refresh now</a><a href="/diagnostics/live_positions?refresh=1">JSON</a><a href="/dashboard">Research dashboard</a><a href="/dashboard?detail=full">Full diagnostics</a></div></div>
    <div class="grid"><div class="card"><div class="muted">Broker Positions</div><div class="metric good">{_dashboard_fmt(summary.get('broker_positions_count'))}</div><table>{_dashboard_rows([('active_plans', summary.get('active_plan_count')),('open_orders', summary.get('open_order_count'))])}</table></div><div class="card"><div class="muted">Trust</div><div class="metric {'bad' if int(summary.get('bad_count') or 0) else 'good'}">{_dashboard_fmt(summary.get('bad_count'))}</div><table>{_dashboard_rows([('warning_count', summary.get('warning_count')),('short_count', summary.get('short_count')),('truth_status', summary.get('position_truth_status')),('mismatches', summary.get('position_truth_mismatch_count'))])}</table></div><div class="card"><div class="muted">Today P&amp;L</div><div class="metric {'good' if _safe_float(pnl.get('today_net_pnl'),0)>=0 else 'bad'}">{_dashboard_money(pnl.get('today_net_pnl'))}</div><table>{_dashboard_rows([('realized', pnl.get('today_realized_pnl')),('unrealized', pnl.get('today_unrealized_pnl')),('closed_trades_today', pnl.get('closed_trades_today')),('source', pnl.get('accounting_source'))])}</table></div><div class="card"><div class="muted">Performance</div><div class="metric good">{_dashboard_fmt(perf.get('closed_trades'))}</div><table>{_dashboard_rows([('wins', perf.get('wins')),('losses', perf.get('losses')),('win_rate', _dashboard_pct(_safe_float(perf.get('win_rate'),0)*100.0)),('gross_pnl', _dashboard_money(perf.get('gross_pnl'))),('avg_r', perf.get('avg_r')),('sample', perf.get('sample_maturity'))])}</table></div></div>
    <div class="card"><h2>Active Positions Audit</h2><table><thead><tr><th>Symbol</th><th>Trust</th><th>Side</th><th>Qty</th><th>Entry</th><th>Last</th><th>U P&amp;L $</th><th>U P&amp;L %</th><th>Stop</th><th>Target</th><th>Signal</th><th>Warnings</th></tr></thead><tbody>{pos_rows}</tbody></table><p class="muted">Trust is based on live broker positions, in-memory/persisted active plans, and open orders. Any missing plan, stale plan, short position, or quantity mismatch is highlighted before you rely on the row.</p></div>
    <div class="card" style="margin-top:14px"><h2>Open Orders</h2><table><thead><tr><th>Symbol</th><th>Side</th><th>Type</th><th>Qty</th><th>Filled</th><th>Status</th><th>Submitted</th></tr></thead><tbody>{order_rows}</tbody></table></div>
    <div class="card" style="margin-top:14px"><h2>Loss Halt Checklist</h2><div class="metric {halt_class}">{'LOSS HALT ACTIVE' if halt.get('daily_halt_active') else 'NO LOSS HALT'}</div><table>{halt_rows}</table><p class="muted">When halted, keep entries blocked, monitor existing positions, verify open orders, and review after the close unless you deliberately override risk policy.</p></div>
    </body></html>'''
    return HTMLResponse(content=html_doc, headers={"Cache-Control": "no-store, max-age=0", "Pragma": "no-cache"})


@app.get("/dashboard", response_class=HTMLResponse)
def dashboard(request: Request):
    """Patch 216: snapshot-only dashboard with lightweight default and full diagnostics on demand."""
    require_admin_if_configured(request)
    dashboard_started = _time.perf_counter()
    generated_utc = datetime.now(timezone.utc).isoformat()
    dashboard_detail = str(request.query_params.get("detail") or request.query_params.get("view") or "summary").strip().lower()
    dashboard_full = dashboard_detail in {"full", "heavy", "debug", "all"}
    dashboard_timings: dict[str, float] = {}

    def _mark_dashboard_phase(name: str):
        dashboard_timings[name] = round((_time.perf_counter() - dashboard_started) * 1000.0, 1)

    def _p210_safe_dict(v):
        return v if isinstance(v, dict) else {}

    def _p210_safe_list(v):
        return v if isinstance(v, list) else []

    _sd = _p210_safe_dict
    _sl = _p210_safe_list

    def _up(v):
        return str(v or "").strip().upper()

    def _read_json(path, fallback=None):
        try:
            p = Path(str(path))
            if not p.exists():
                return fallback or {}
            raw = p.read_text(encoding="utf-8")
            return json.loads(raw) if raw.strip() else (fallback or {})
        except Exception as exc:
            out = fallback or {}
            if isinstance(out, dict):
                out = dict(out)
                out["_read_error"] = str(exc)
            return out

    def _first(row, *keys):
        row = _p210_safe_dict(row)
        for k in keys:
            v = row.get(k)
            if v not in (None, ""):
                return v
        return None

    def _flt(v, default=0.0):
        try:
            if v in (None, ""):
                return default
            return float(v)
        except Exception:
            return default

    def _money(v):
        if v in (None, ""):
            return "—"
        try:
            return _dashboard_money(v)
        except Exception:
            try:
                return f"${float(v):,.2f}"
            except Exception:
                return html.escape(str(v))

    def _pct(v):
        try:
            return _dashboard_pct(float(v))
        except Exception:
            return "—"

    def _rows(items):
        try:
            return _dashboard_rows(items)
        except Exception:
            return "".join(f"<tr><th>{html.escape(str(k))}</th><td>{html.escape(str(v))}</td></tr>" for k, v in items)

    # Snapshot/state files only. The dashboard does not execute broker, reconcile, scanner, or exit work.
    # Default /dashboard is summary-first; use /dashboard?detail=full for heavier analytics panels.
    snap = _p210_safe_dict(_read_json(globals().get("POSITION_SNAPSHOT_PATH") or os.getenv("POSITION_SNAPSHOT_PATH") or "/var/data/positions_snapshot.json", {}))
    scan_state = _p210_safe_dict(_read_json(globals().get("SCAN_STATE_PATH") or os.getenv("SCAN_STATE_PATH") or "/var/data/scan_state.json", {}))
    regime_state = _p210_safe_dict(_read_json(globals().get("REGIME_STATE_PATH") or os.getenv("REGIME_STATE_PATH") or "/var/data/regime_state.json", {}))
    scanner_state = _sd(_read_json(globals().get("SCANNER_TELEMETRY_STATE_PATH") or os.getenv("SCANNER_TELEMETRY_STATE_PATH") or "/var/data/scanner_telemetry_state.json", {}))
    lifecycle_state = _sd(_read_json(globals().get("PAPER_LIFECYCLE_STATE_PATH") or os.getenv("PAPER_LIFECYCLE_STATE_PATH") or "/var/data/paper_lifecycle_state.json", {}))
    perf_payload = _sd(_read_json(globals().get("STRATEGY_PERFORMANCE_STATE_PATH") or os.getenv("STRATEGY_PERFORMANCE_STATE_PATH") or "/var/data/strategy_performance_state.json", {}))
    perf_state = _sd(perf_payload.get("state") if isinstance(perf_payload, dict) else {}) or perf_payload
    _mark_dashboard_phase("snapshot_load_ms")

    snap_extra = _sd(snap.get("extra"))
    loss_control_incident = _sd(snap_extra.get("loss_control_incident"))
    current_dashboard_session = _current_session_key()
    incident_session = str(loss_control_incident.get("session") or "")
    if loss_control_incident and incident_session and incident_session != current_dashboard_session:
        loss_control_incident = dict(loss_control_incident)
        loss_control_incident["active"] = False
        loss_control_incident["stale_session"] = incident_session
        loss_control_incident["recommended_action"] = "prior_session_incident_review_only"
        loss_control_incident["recommended_actions"] = ["prior_session_incident_review_only"]
    snapshot_today_pnl_truth = _sd(snap_extra.get("today_pnl_truth") or loss_control_incident)
    snapshot_daily_halt_truth = _sd(snap_extra.get("daily_halt_truth"))

    positions = _p210_safe_list(snap.get("positions"))
    active_plans = _sd(snap.get("active_plans")) or _sd(globals().get("TRADE_PLAN") or {})
    snap_summary = _sd(snap.get("summary"))
    latest_scan = _sd(scan_state.get("last_scan") or scan_state.get("last") or {})
    scan_summary = _sd(latest_scan.get("summary"))
    regime_current = _sd(regime_state.get("current") or regime_state.get("last") or regime_state)
    scanner_summary = _sd(scanner_state.get("summary") or scanner_state.get("last") or {})
    scanner_last = _sd(scanner_state.get("last") or scanner_state.get("summary") or {})
    lifecycle_history = _p210_safe_list(lifecycle_state.get("history"))[-8:]
    perf_by_strategy = _sd(perf_state.get("by_strategy"))

    closed_trade_rows = _sl(perf_state.get("closed_trades") or perf_state.get("closed_positions") or perf_state.get("trades_closed"))
    
    def _snapshot_display(v, fallback="snapshot unavailable"):
        return v if v not in (None, "") else fallback

    def _snapshot_value(v, fallback="snapshot unavailable"):
        return v if v not in (None, "") else fallback

    def _strategy_name_from_row(row: dict) -> str:
        return str(row.get("strategy_name") or row.get("strategy") or row.get("signal") or row.get("entry_signal") or "unknown").strip() or "unknown"

    def _aggregate_strategy_from_closed(rows: list[dict]) -> dict:
        out = {}
        for item in rows:
            row = _sd(item)
            name = _strategy_name_from_row(row)
            bucket = out.setdefault(name, {"closed_trades": 0, "wins": 0, "losses": 0, "flat": 0, "gross_pnl": 0.0, "_r_sum": 0.0, "_r_count": 0})
            bucket["closed_trades"] += 1
            pnl = _first(row, "realized_pnl", "pnl", "gross_pnl", "profit_loss")
            pnl_f = _flt(pnl) if pnl not in (None, "") else 0.0
            bucket["gross_pnl"] += pnl_f
            if pnl_f > 0: bucket["wins"] += 1
            elif pnl_f < 0: bucket["losses"] += 1
            else: bucket["flat"] += 1
            r_val = _first(row, "r", "r_multiple", "realized_r")
            if r_val not in (None, ""):
                bucket["_r_sum"] += _flt(r_val)
                bucket["_r_count"] += 1
        for b in out.values():
            ct = max(1, int(b.get("closed_trades") or 0))
            b["win_rate"] = float(b.get("wins") or 0) / float(ct)
            rc = int(b.get("_r_count") or 0)
            b["avg_r"] = (float(b.get("_r_sum") or 0.0) / float(rc)) if rc > 0 else 0.0
        return out


    pos_by_symbol = {}
    for p in positions:
        if isinstance(p, dict):
            sym = _up(p.get("symbol"))
            if sym:
                pos_by_symbol[sym] = p
    plan_by_symbol = {}
    for sym, plan in active_plans.items():
        if isinstance(plan, dict):
            usym = _up(sym or plan.get("symbol"))
            if usym:
                plan_by_symbol[usym] = plan
    active_plan_symbols = {sym for sym, plan in plan_by_symbol.items() if bool(_sd(plan).get("active"))}
    row_symbols = sorted(set(pos_by_symbol.keys()) | active_plan_symbols)
    position_truth = _position_truth_snapshot(snapshot=snap, reconcile=None, live=False)
    worker_exit_view = _worker_exit_status_snapshot(limit=8)
    
    try:
        now_local = now_ny()
        market_open = bool(in_market_hours())
        now_ny_text = now_local.isoformat()
    except Exception:
        market_open = False
        now_ny_text = "unknown"

    kill_switch = bool(globals().get("KILL_SWITCH", False))
    dry_run = bool(globals().get("DRY_RUN", False))
    live_enabled = bool(globals().get("LIVE_TRADING_ENABLED", False))
    daily_halt_state = _sd(globals().get("DAILY_HALT_STATE") or {})
    try:
        daily_halt_active_value = bool(daily_halt_active())
    except Exception:
        daily_halt_active_value = bool(daily_halt_state.get("active") or daily_halt_state.get("daily_halt_active"))
    dashboard_daily_halt_reason = (
        daily_halt_state.get("reason")
        or daily_halt_state.get("daily_halt_reason")
        or snapshot_daily_halt_truth.get("daily_halt_reason")
        or "none"
    ) if daily_halt_active_value else "none"
    live_orders = bool(live_enabled and not kill_switch and not dry_run and not daily_halt_active_value)

    merged = []
    total_unrealized = 0.0
    winners = 0
    losers = 0
    for sym in row_symbols:
        pos = _sd(pos_by_symbol.get(sym))
        plan = _sd(plan_by_symbol.get(sym))
        qty = _first(pos, "qty") or _first(plan, "filled_qty", "qty", "submitted_qty", "requested_qty")
        entry = _first(pos, "avg_entry_price") or _first(plan, "entry_price", "avg_fill_price", "filled_avg_price")
        stop = _first(plan, "stop_price", "initial_stop_price")
        target = _first(plan, "take_price", "target_price", "initial_take_price")
        signal = _first(plan, "signal", "strategy_name") or ("broker_position" if pos else "")
        if bool(plan.get("recovered")) and bool(plan.get("attribution_backfilled")) and str(signal or "").upper() in {"RECOVERED", "RECOVERED_OPEN_ORDER"}:
            signal = _first(plan, "strategy_name") or signal
        status = _first(plan, "execution_state", "lifecycle_state", "order_status") or ("broker_position" if pos else "")
        days = _first(plan, "days_held")
        if days in (None, "", 0, "0") and plan:
            days = plan_days_held(plan)
        last = _first(pos, "current_price", "last_price", "latest_price", "market_price") or _first(plan, "last_price", "current_price", "latest_price")
        upl = _first(pos, "unrealized_pl", "unrealized_intraday_pl")
        if upl is None and last is not None and entry is not None and qty is not None:
            upl = (_flt(last) - _flt(entry)) * _flt(qty)
        if upl not in (None, ""):
            u = _flt(upl)
            total_unrealized += u
            if u > 0:
                winners += 1
            elif u < 0:
                losers += 1
        merged.append({"symbol": sym, "qty": qty, "entry": entry, "last": last, "upl": upl, "stop": stop, "target": target, "signal": signal, "status": status, "days": days})

    active_rows = "".join(
        "<tr>"
        f"<td>{html.escape(str(r['symbol']))}</td>"
        f"<td>{_dashboard_fmt(r['qty'])}</td>"
        f"<td>{_dashboard_fmt(r['entry'])}</td>"
        f"<td>{_dashboard_fmt(_snapshot_display(r['last']))}</td>"
        f"<td>{_money(r['upl']) if r['upl'] not in (None, '') else 'snapshot unavailable'}</td>"
        f"<td>{_dashboard_fmt(r['stop'])}</td>"
        f"<td>{_dashboard_fmt(r['target'])}</td>"
        f"<td>{html.escape(str(r['signal'] or ''))}</td>"
        f"<td>{html.escape(str(r['status'] or ''))}</td>"
        f"<td>{_dashboard_fmt(r['days'])}</td>"
        "</tr>" for r in merged
    ) or '<tr><td colspan="10" class="muted">No active positions in latest snapshot.</td></tr>'
    _mark_dashboard_phase("position_merge_ms")

    row_strategy_perf = _aggregate_strategy_from_closed(closed_trade_rows)
    by_strategy_count = int(sum(int(_sd(b).get("closed_trades") or 0) for b in perf_by_strategy.values())) if perf_by_strategy else 0
    row_strategy_count = int(sum(int(_sd(b).get("closed_trades") or 0) for b in row_strategy_perf.values()))
    strategy_perf = perf_by_strategy if by_strategy_count >= row_strategy_count and perf_by_strategy else row_strategy_perf
    closed_trades = int(sum(int(_sd(b).get("closed_trades") or 0) for b in strategy_perf.values()))
    wins = int(sum(int(_sd(b).get("wins") or 0) for b in strategy_perf.values()))
    losses = int(sum(int(_sd(b).get("losses") or 0) for b in strategy_perf.values()))
    flat = int(sum(int(_sd(b).get("flat") or 0) for b in strategy_perf.values()))
    gross_pnl = round(sum(_flt(_sd(b).get("gross_pnl")) for b in strategy_perf.values()), 4)
    avg_r = round(sum(_flt(_sd(b).get("avg_r")) * int(_sd(b).get("closed_trades") or 0) for b in strategy_perf.values()) / max(1, closed_trades), 4)
    win_rate = wins / max(1, closed_trades)
    maturity = "LOW SAMPLE" if closed_trades < 30 else ("BUILDING" if closed_trades < 75 else "ESTABLISHED")
    maturity_class = "bad" if closed_trades < 10 else ("neutral" if closed_trades < 30 else "good")
    swing_capacity_advisory = _swing_capacity_advisory(
        current_max=_effective_max_open_positions(),
        current_open_positions=len(merged),
        closed_trades=closed_trades,
        win_rate=win_rate,
        avg_r=avg_r,
    )
    if dashboard_full:
        swing_attribution = _swing_performance_attribution(perf_state=perf_state)
    else:
        swing_attribution = {
            "risk_scaling": {
                "current_risk_dollars": round(float(RISK_DOLLARS or 0.0), 2),
                "recommended_risk_dollars": round(float(RISK_DOLLARS or 0.0), 2),
                "ready_for_40_risk": False,
                "ready_for_50_risk": False,
                "blockers": ["open_full_diagnostics_for_attribution"],
            },
            "risk_blocker_explanation": {
                "risk_scale_next_required_fix": "open_dashboard_detail_full_for_attribution",
            },
            "quarantine_controls": {
                "symbols": sorted(SWING_QUARANTINE_SYMBOLS),
                "strategies": sorted(SWING_QUARANTINE_STRATEGIES),
                "entry_types": sorted(SWING_QUARANTINE_ENTRY_TYPES),
                "enforced": bool(SWING_QUARANTINE_ENFORCE),
            },
        }
    swing_risk_scaling = _sd(swing_attribution.get("risk_scaling"))

    def _p207_rows(bucket_rows, limit=6):
        out = []
        for bucket in _sl(bucket_rows)[:limit]:
            b = _sd(bucket)
            out.append(f"<tr><td>{html.escape(str(b.get('name') or 'unknown'))}</td><td>{_dashboard_fmt(b.get('closed_trades'))}</td><td>{_pct(_flt(b.get('win_rate')) * 100.0)}</td><td>{_money(b.get('gross_pnl'))}</td><td>{_dashboard_fmt(b.get('avg_r')) if b.get('avg_r') is not None else '—'}R</td></tr>")
        return ''.join(out) or '<tr><td colspan="5" class="muted">No closed trade attribution available.</td></tr>'

    def _p207_reco_text(kind):
        rows = _sl(_sd(swing_attribution.get('recommendations')).get(kind))
        return ', '.join(f"{_sd(r).get('category')}:{_sd(r).get('name')}({_dashboard_fmt(_sd(r).get('avg_r'))}R)" for r in rows[:5]) or 'none'

    p207_symbol_rows = _p207_rows(swing_attribution.get('by_symbol'), limit=8) if dashboard_full else '<tr><td colspan="5" class="muted">Open /dashboard?detail=full for symbol attribution.</td></tr>'
    p207_strategy_rows = _p207_rows(swing_attribution.get('by_strategy'), limit=6) if dashboard_full else '<tr><td colspan="5" class="muted">Open /dashboard?detail=full for strategy attribution.</td></tr>'
    p207_entry_rows = _p207_rows(swing_attribution.get('by_entry_type'), limit=6) if dashboard_full else '<tr><td colspan="5" class="muted">Open /dashboard?detail=full for entry attribution.</td></tr>'
    p207_exit_rows = _p207_rows(swing_attribution.get('by_exit_reason'), limit=6) if dashboard_full else '<tr><td colspan="5" class="muted">Open /dashboard?detail=full for exit attribution.</td></tr>'
    p207_holding_rows = _p207_rows(swing_attribution.get('by_holding_period'), limit=6) if dashboard_full else '<tr><td colspan="5" class="muted">Open /dashboard?detail=full for holding-period attribution.</td></tr>'
    p207_promote_text = _p207_reco_text('promote')
