@app.get("/diagnostics/intraday_launch_readiness")
def diagnostics_intraday_launch_readiness(request: Request):
    require_admin_if_configured(request)
    projection = _intraday_launch_projection()
    projected = dict(projection.get("projected_intraday") or {})
    effective_daily_stop = projected.get("daily_stop_dollars")
    effective_daily_loss_limit = projected.get("daily_loss_limit")
    effective_max_positions = projected.get("max_open_positions")
    effective_portfolio_cap = projected.get("portfolio_exposure_cap_pct")
    effective_symbol_cap = projected.get("symbol_exposure_cap_pct")
    try:
        market_tradable_now = bool(in_market_hours())
    except Exception:
        market_tradable_now = False
    regime_snapshot = dict(LAST_REGIME_SNAPSHOT or {})
    regime_favorable = bool(regime_snapshot.get("favorable"))
    checks = [
        {"name": "live_trading_enabled", "ok": bool(LIVE_TRADING_ENABLED), "value": bool(LIVE_TRADING_ENABLED), "note": "Must be true to place live intraday orders."},
        {"name": "only_market_hours", "ok": bool(ONLY_MARKET_HOURS), "value": bool(ONLY_MARKET_HOURS), "note": "Recommended true for intraday launch discipline."},
        {"name": "market_tradable_now", "ok": market_tradable_now, "value": market_tradable_now, "note": "Intraday launch should wait until the market is tradable."},
        {"name": "regime_favorable", "ok": regime_favorable, "value": {"favorable": regime_snapshot.get("favorable"), "score": regime_snapshot.get("score"), "breadth": regime_snapshot.get("breadth"), "data_complete": regime_snapshot.get("data_complete")}, "note": "Intraday launch should wait for a favorable regime unless the operator intentionally overrides regime gating."},
        {"name": "dry_run", "ok": not bool(DRY_RUN), "value": bool(DRY_RUN), "note": "Must be false to execute real orders."},
        {"name": "max_open_positions", "ok": int(effective_max_positions) >= 7, "value": int(effective_max_positions), "note": "Capacity floor check for launch-day opportunity set."},
        {"name": "projected_open_slots_available", "ok": int(projected.get("open_slots_available") or 0) > 0, "value": int(projected.get("open_slots_available") or 0), "note": "Launch should have at least one projected slot; current dashboard is full at 7/7."},
        {"name": "projected_open_slots_meet_launch_min", "ok": int(projected.get("open_slots_available") or 0) >= int(projection.get("launch_min_open_slots") or 1), "value": {"projected_open_slots": int(projected.get("open_slots_available") or 0), "launch_min_open_slots": int(projection.get("launch_min_open_slots") or 1), "recommended_intraday_max_open_positions": int(projection.get("recommended_intraday_max_open_positions") or 0)}, "note": "Set INTRADAY_MAX_OPEN_POSITIONS to the recommendation before launch so intraday has spare capacity."},
        {"name": "intraday_capacity_override_above_base", "ok": "intraday_max_open_positions_not_above_base" not in set(projection.get("blockers") or []), "value": projection.get("configured_intraday_overrides", {}).get("max_open_positions"), "note": "Set INTRADAY_MAX_OPEN_POSITIONS above base for extra scale; this is blocking only when projected slots are below the launch minimum."},
        {"name": "entry_require_fresh_quote", "ok": bool(ENTRY_REQUIRE_FRESH_QUOTE), "value": bool(ENTRY_REQUIRE_FRESH_QUOTE), "note": "Should remain enabled for fast intraday fills."},
        {"name": "swing_allow_same_day_exit", "ok": bool(SWING_ALLOW_SAME_DAY_EXIT), "value": bool(SWING_ALLOW_SAME_DAY_EXIT), "note": "Set true if the same strategy stack is expected to permit same-day exits."},
        {"name": "effective_daily_stop_dollars", "ok": float(effective_daily_stop) >= 150.0, "value": float(effective_daily_stop), "note": "Raise this if you want to avoid early daily-stop blocking for intraday scaling."},
        {"name": "effective_daily_loss_limit", "ok": float(effective_daily_loss_limit) >= 150.0, "value": float(effective_daily_loss_limit), "note": "Raise this if you want to avoid conservative daily-loss gating for intraday scaling."},
        {"name": "effective_portfolio_exposure_cap_pct", "ok": float(effective_portfolio_cap) >= 0.90, "value": float(effective_portfolio_cap), "note": "Increase cautiously if you want more intraday capital deployment."},
        {"name": "effective_symbol_exposure_cap_pct", "ok": float(effective_symbol_cap) >= 0.35, "value": float(effective_symbol_cap), "note": "Increase cautiously if you want bigger single-name intraday sizing."},
    ]
    required_check_names = {
        "live_trading_enabled",
        "market_tradable_now",
        "regime_favorable",
        "dry_run",
        "projected_open_slots_available",
        "projected_open_slots_meet_launch_min",
    }
    for check in checks:
        check["required_for_launch"] = check.get("name") in required_check_names
    blockers = [c.get("name") for c in checks if c.get("required_for_launch") and not c.get("ok")]
    recommended_followups = [c.get("name") for c in checks if not c.get("required_for_launch") and not c.get("ok")]
    live_preflight = _intraday_live_preflight()
    for preflight_blocker in live_preflight.get("blockers") or []:
        if preflight_blocker not in blockers:
            blockers.append(preflight_blocker)
    launch_gate_actions = _intraday_launch_gate_actions(blockers)
    launch_action_plan = _intraday_launch_action_plan(
        gate_actions=launch_gate_actions,
        required_actions=projection.get("next_actions"),
        optional_scaling_actions=projection.get("optional_actions"),
        recommended_env=projection.get("recommended_env"),
    )
    return {
        "ok": True,
        "patch_version": PATCH_VERSION,
        "effective_date_utc": "2026-06-04",
        "framework": "finra_intraday_margin",
        "strategy_mode": str(globals().get("STRATEGY_MODE") or ""),
        "projection": projection,
        "launch_gate_status": {"market_tradable_now": market_tradable_now, "regime_favorable": regime_favorable},
        "intraday_live_preflight": live_preflight,
        "launch_gate_actions": launch_gate_actions,
        "launch_action_plan": launch_action_plan,
        "score_passed": len(checks) - len(blockers),
        "score_total": len(checks),
        "ready": not blockers and not projection.get("blockers"),
        "blockers": _unique_nonempty_actions(blockers, projection.get("blockers")),
        "recommended_followups": recommended_followups,
        "checks": checks,
    }

